export interface Product {
  id: string;
  sku: string;
  parentSku: string;
  name: string;
  description: string;
  imageUrl: string;
  productUrl: string;
  price: string;
  comparePrice?: string;
  currency: string;
  color: string;
  size: string;
  category: string;
