    countryCode: settings.deliveryCountries[0]?.code || 'FR',
    salesChannel: settings.orderSalesChannels[0] || ''
  });

  const [generatedData, setGeneratedData] = useState<{ parent: any, subOrders: any[] } | null>(null);
  const [copyStatus, setCopyStatus] = useState<string | null>(null);

  const handleGenerate = () => {
    if (products.length === 0) {
      alert("No products available to generate orders.");
      return;
    }
    const data = generateOrderPayloads(request, products, settings);
    setGeneratedData(data);
  };

  const handleCopy = (content: any, label: string) => {
    navigator.clipboard.writeText(JSON.stringify(content, null, 4));
    setCopyStatus(label);
    setTimeout(() => setCopyStatus(null), 2000);
  };

  const handleDownloadAll = () => {
    if (!generatedData) return;
    const combined = {
      parent_order: generatedData.parent,
      sub_orders: generatedData.subOrders
    };
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(combined, null, 4));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", `onestock_orders_package_${Date.now()}.json`);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500 pb-20">
      <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-8">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-8">
          <div>
            <h2 className="text-2xl font-bold text-[#002D72]">Customer Order Generation</h2>
            <p className="text-sm text-gray-500 mt-1">Simulate real customer traffic using {products.length} imported articles.</p>
          </div>
          <div className="flex gap-3">
            <button onClick={onCancel} className="px-4 py-2 text-sm font-semibold text-gray-600 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors">Cancel</button>
            <button 
              onClick={handleGenerate}
              className="px-6 py-2 bg-[#002D72] text-white font-bold rounded-lg hover:bg-[#001F4D] shadow-lg flex items-center gap-2 transition-all text-sm"
            >
              Generate New Batch
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.5 14.25v-2.625a3.375 3.375 0 00-3.375-3.375h-1.5A1.125 1.125 0 0113.5 7.125v-1.5a3.375 3.375 0 00-3.375-3.375H8.25m3.75 9v6m3-3H9m1.5-12H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 00-9-9z" /></svg>
            </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 p-6 bg-gray-50 rounded-xl border border-gray-100">
          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Order Strategy</label>
            <div className="grid grid-cols-3 gap-2">
              {(['sfs', 'ckc', 'ropis'] as const).map(t => (
                <button 
                  key={t}
                  onClick={() => setRequest(prev => ({ ...prev, type: t }))}
                  className={`py-2 text-[10px] font-bold rounded-lg uppercase tracking-wider transition-all border ${
                    request.type === t ? 'bg-[#002D72] border-[#002D72] text-white' : 'bg-white border-gray-200 text-gray-400 hover:border-blue-200'
                  }`}
                >
                  {t}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Destination Country</label>
            <select 
              value={request.countryCode}
              onChange={e => setRequest(prev => ({ ...prev, countryCode: e.target.value }))}
              className="w-full px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-bold text-onestock-blue outline-none focus:border-onestock-blue"
            >
              {settings.deliveryCountries.map(c => (
                <option key={c.code} value={c.code}>{c.name} ({c.code})</option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Sales Channel</label>
            <select 
              value={request.salesChannel}
              onChange={e => setRequest(prev => ({ ...prev, salesChannel: e.target.value }))}
              className="w-full px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-bold text-onestock-blue outline-none focus:border-onestock-blue"
            >
              {settings.orderSalesChannels.map(sc => (
                <option key={sc} value={sc}>{sc}</option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Order Count</label>
            <input 
              type="number" min="1" max="50"
              value={request.count}
              onChange={e => setRequest(prev => ({ ...prev, count: parseInt(e.target.value) || 1 }))}
              className="w-full px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-bold text-onestock-blue"
            />
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Items per Order</label>
            <input 
              type="number" min="1" max="10"
              value={request.productsPerOrder}
              onChange={e => setRequest(prev => ({ ...prev, productsPerOrder: parseInt(e.target.value) || 1 }))}
              className="w-full px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-bold text-onestock-blue"
            />
          </div>

          <div className="flex items-end">
            <div className="w-full p-2 bg-blue-50/50 rounded-lg border border-blue-100 flex items-center gap-2">
              <svg className="w-4 h-4 text-onestock-blue" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
              <span className="text-[10px] text-onestock-blue font-medium">Order IDs will follow: <strong className="uppercase">{request.type}-00000001</strong></span>
            </div>
          </div>
        </div>
      </div>

      {generatedData && (
        <div className="space-y-6 animate-in fade-in slide-in-from-top-4">
          <div className="flex items-center justify-between">
            <h3 className="text-lg font-bold text-[#002D72] flex items-center gap-2">
              Generated JSON Package
              <span className="text-xs font-medium px-2 py-0.5 bg-blue-100 text-blue-700 rounded-full">
                1 Parent + {generatedData.subOrders.length} Sub-Orders
              </span>
            </h3>
            <button 
              onClick={handleDownloadAll}
              className="px-4 py-2 text-xs font-bold text-onestock-blue border border-onestock-blue rounded-lg hover:bg-blue-50 transition-all flex items-center gap-2"
            >
              Download Full Package (.json)
            </button>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="space-y-4">
              <div className="bg-[#001F4D] rounded-xl overflow-hidden shadow-xl border border-white/10">
                <div className="px-4 py-2 bg-white/5 border-b border-white/10 flex justify-between items-center">
                  <span className="text-[10px] font-bold text-blue-300 uppercase tracking-widest">Parent Order Payload</span>
                  <button 
                    onClick={() => handleCopy(generatedData.parent, 'parent')}
                    className="text-[10px] font-bold text-white/40 hover:text-white transition-colors"
                  >
                    {copyStatus === 'parent' ? 'COPIED!' : 'COPY'}
                  </button>
                </div>
                <div className="p-4 overflow-y-auto max-h-48 text-[11px] font-mono text-blue-100">
                  <pre>{JSON.stringify(generatedData.parent, null, 2)}</pre>
                </div>
              </div>

              {generatedData.subOrders.slice(0, 1).map((order, idx) => (
                <div key={idx} className="bg-[#001F4D] rounded-xl overflow-hidden shadow-xl border border-white/10">
                  <div className="px-4 py-2 bg-white/5 border-b border-white/10 flex justify-between items-center">
                    <span className="text-[10px] font-bold text-blue-300 uppercase tracking-widest">Example Sub-Order (1/{generatedData.subOrders.length})</span>
                    <button 
                      onClick={() => handleCopy(order, `sub-${idx}`)}
                      className="text-[10px] font-bold text-white/40 hover:text-white transition-colors"
                    >
                      {copyStatus === `sub-${idx}` ? 'COPIED!' : 'COPY'}
                    </button>
                  </div>
                  <div className="p-4 overflow-y-auto max-h-96 text-[11px] font-mono text-blue-100">
                    <pre>{JSON.stringify(order, null, 2)}</pre>
                  </div>
                </div>
              ))}

              {generatedData.subOrders.length > 1 && (
                <div className="p-4 bg-white rounded-xl border border-gray-200 text-center text-xs text-gray-500 italic">
                  + {generatedData.subOrders.length - 1} more sub-order payloads generated. 
                  Download the full package to view all.
                </div>
              )}
            </div>

            <div className="space-y-4">
              <div className="bg-white rounded-xl border border-gray-200 p-6 shadow-sm">
                <h4 className="text-xs font-bold text-[#002D72] uppercase tracking-widest mb-4">Simulation Summary</h4>
                <div className="space-y-4">
                  <div className="flex justify-between items-center py-2 border-b border-gray-50">
                    <span className="text-xs text-gray-400 uppercase font-bold tracking-tighter">Country Code</span>
                    <span className="text-sm font-bold text-onestock-blue">{request.countryCode}</span>
                  </div>
                  <div className="flex justify-between items-center py-2 border-b border-gray-50">
                    <span className="text-xs text-gray-400 uppercase font-bold tracking-tighter">Sales Channel</span>
                    <span className="text-sm font-bold text-onestock-blue">{request.salesChannel}</span>
                  </div>
                  <div className="flex justify-between items-center py-2 border-b border-gray-50">
                    <span className="text-xs text-gray-400 uppercase font-bold tracking-tighter">Total Gross Value</span>
                    <span className="text-sm font-bold text-onestock-blue">
                      {generatedData.parent.parent_order.pricing_details.price} {generatedData.parent.parent_order.pricing_details.currency}
                    </span>
                  </div>
                  <div className="flex justify-between items-center py-2 border-b border-gray-50">
                    <span className="text-xs text-gray-400 uppercase font-bold tracking-tighter">Order ID Pattern</span>
                    <span className="text-[10px] bg-blue-100 text-blue-700 px-2 py-0.5 rounded-full font-bold uppercase tracking-wider">
                      {request.type.toUpperCase()}-00000001
                    </span>
                  </div>
                </div>

                <div className="mt-8 p-4 bg-green-50 rounded-lg border border-green-100 flex items-start gap-3">
                  <svg className="w-5 h-5 text-green-600 shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                  <p className="text-[11px] text-green-800 leading-relaxed">
                    <strong>Ready for Postman:</strong> These payloads are fully compliant with the OneStock OMS API. You can copy the parent order first, then the sub-orders using the generated parent ID.
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {products.length === 0 && (
        <div className="bg-yellow-50 border border-yellow-100 p-12 rounded-2xl text-center">
           <svg className="w-12 h-12 text-yellow-500 mx-auto mb-4 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
           <h3 className="text-lg font-bold text-yellow-800">No Articles Detected</h3>
           <p className="text-sm text-yellow-700 mt-2">You must complete a website import before generating customer orders.</p>
        </div>
      )}
    </div>
  );
};

export default StepOrderGeneration;

import React, { useState, useRef } from 'react';
import { AppSettings, Product } from '../types';

interface SettingsProps {
  settings: AppSettings;
  onSave: (settings: AppSettings) => void;
}

const Settings: React.FC<SettingsProps> = ({ settings, onSave }) => {
  const [newEndpoint, setNewEndpoint] = useState('');
  const [newOrderChannel, setNewOrderChannel] = useState('');
  const [newRuleset, setNewRuleset] = useState('');
  const [newCountryCode, setNewCountryCode] = useState('');
  const [newCountryName, setNewCountryName] = useState('');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    onSave({
      ...settings,
      [name]: type === 'number' ? parseFloat(value) : value,
    });
  };

  const handleMappingChange = (onestockField: string, productField: string) => {
    onSave({
      ...settings,
      fieldMapping: {
        ...settings.fieldMapping,
        [onestockField]: productField as keyof Product | 'none'
      }
    });
  };

  const addItem = (field: keyof AppSettings, value: string, setter: React.Dispatch<React.SetStateAction<string>>) => {
    if (value.trim()) {
      const currentList = settings[field] as string[];
      if (!currentList.includes(value.trim())) {
        onSave({ ...settings, [field]: [...currentList, value.trim()] });
        setter('');
      }
    }
  };

  const addCountry = () => {
    if (newCountryCode.trim() && newCountryName.trim()) {
      if (!settings.deliveryCountries.some(c => c.code === newCountryCode.trim())) {
        onSave({
          ...settings,
          deliveryCountries: [...settings.deliveryCountries, { code: newCountryCode.trim().toUpperCase(), name: newCountryName.trim() }]
        });
        setNewCountryCode('');
        setNewCountryName('');
      }
    }
  };

  const removeItem = (field: keyof AppSettings, value: string) => {
    const currentList = settings[field] as string[];
    onSave({ ...settings, [field]: currentList.filter(v => v !== value) });
  };

  const removeCountry = (code: string) => {
    onSave({
      ...settings,
      deliveryCountries: settings.deliveryCountries.filter(c => c.code !== code)
    });
  };

  const renderListManager = (
    label: string, 
    field: keyof AppSettings, 
    value: string, 
    setter: React.Dispatch<React.SetStateAction<string>>,
    placeholder: string
  ) => (
    <div className="space-y-4">
      <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest">{label}</label>
      <div className="flex gap-2">
        <input 
          value={value} 
          onChange={(e) => setter(e.target.value)} 
          className="flex-1 px-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none" 
          placeholder={placeholder}
        />
        <button 
          onClick={() => addItem(field, value, setter)}
          className="px-4 py-2 bg-onestock-blue text-white font-bold text-xs rounded-lg hover:bg-[#001F4D]"
        >
          Add
        </button>
      </div>
      <div className="flex flex-wrap gap-2">
        {(settings[field] as string[]).map(v => (
          <div key={v} className="bg-blue-50 border border-blue-100 px-3 py-1.5 rounded-lg flex items-center gap-2">
            <span className="text-xs font-mono font-bold text-onestock-blue">{v}</span>
            <button onClick={() => removeItem(field, v)} className="text-blue-300 hover:text-red-500">
              <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
        ))}
      </div>
    </div>
  );

  const productFields: (keyof Product | 'none')[] = [
    'none', 'sku', 'parentSku', 'name', 'description', 'price', 'color', 'size', 'imageUrl'
  ];

  const coreFields = [
    { key: 'id', label: 'Item ID (Unique SKU)', required: true, desc: 'Primary identifier for the article.' },
    { key: 'product_id', label: 'Product ID (Mother ID)', required: true, desc: 'Groups multiple variants under one product.' },
    { key: 'name', label: 'Label / Name', required: true, desc: 'Public display name of the item.' },
  ];

  const featureFields = [
    { key: 'price', label: 'Unit Price', desc: 'Base price used if sales channel price is empty.' },
    { key: 'description', label: 'Description', desc: 'Long text detailing the product.' },
    { key: 'color', label: 'Color Variant', desc: 'The specific color of this SKU.' },
    { key: 'size', label: 'Size Variant', desc: 'The specific size of this SKU.' },
    { key: 'image', label: 'Main Image URL', desc: 'Direct link to the primary visual.' },
    { key: 'brand', label: 'Brand Name', desc: 'Manufacturer or label name.' },
    { key: 'category', label: 'Category Path', desc: 'Breadcrumb or category identifier.' },
  ];

  const renderMappingRow = (field: { key: string, label: string, required?: boolean, desc: string }) => {
    const currentMapping = (settings.fieldMapping as any)[field.key];
    const isMapped = currentMapping && currentMapping !== 'none';

    return (
      <div 
        key={field.key} 
        className={`grid grid-cols-12 gap-4 items-center p-4 rounded-xl transition-all border ${
          isMapped ? 'bg-blue-50/40 border-blue-100' : 'bg-white border-transparent hover:bg-gray-50'
        }`}
      >
        <div className="col-span-5">
          <div className="flex items-center gap-2">
            <span className={`text-sm font-bold ${isMapped ? 'text-[#002D72]' : 'text-gray-700'}`}>{field.label}</span>
            {field.required && (
              <span className="text-[8px] bg-red-50 text-red-600 px-1.5 py-0.5 rounded font-bold uppercase tracking-tighter">Required</span>
            )}
          </div>
          <p className="text-[10px] text-gray-400 mt-0.5 leading-tight">{field.desc}</p>
        </div>
        <div className="col-span-2 flex items-center justify-center">
          <div className={`w-10 h-px ${isMapped ? 'bg-blue-300' : 'bg-gray-200'}`}></div>
        </div>
        <div className="col-span-5">
          <select 
            value={currentMapping || 'none'}
            onChange={(e) => handleMappingChange(field.key, e.target.value)}
            className={`w-full border rounded-lg px-3 py-2 text-sm font-medium outline-none transition-all ${
              isMapped ? 'bg-white border-blue-300 text-[#002D72]' : 'bg-white border-gray-200 text-gray-400'
            }`}
          >
            {productFields.map(pf => (
              <option key={pf} value={pf}>{pf === 'none' ? '-- Unmapped --' : pf}</option>
            ))}
          </select>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-8">
        <div className="border-b border-gray-100 pb-6 mb-8 flex justify-between items-center">
          <div>
            <h2 className="text-2xl font-bold text-gray-900">API Gateway Configuration</h2>
            <p className="text-gray-500 text-sm mt-1">Connectivity details for the <strong>{settings.apiName}</strong>.</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
          <div className="space-y-6">
            <h3 className="text-xs font-bold text-[#002D72] uppercase tracking-widest border-l-4 border-[#002D72] pl-3">Connection Identity</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-1.5">Custom API Label</label>
                <input name="apiName" value={settings.apiName} onChange={handleChange} className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl text-sm outline-none font-bold text-gray-800" />
              </div>
              <div>
                <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-1.5">Base API URL</label>
                <input name="apiUrl" value={settings.apiUrl} onChange={handleChange} className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl text-sm outline-none" />
              </div>
            </div>
          </div>

          <div className="space-y-6">
            <h3 className="text-xs font-bold text-[#002D72] uppercase tracking-widest border-l-4 border-[#002D72] pl-3">Security & Context</h3>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-1.5">Site Context ID</label>
                <input name="siteId" value={settings.siteId} onChange={handleChange} className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl text-sm outline-none" />
              </div>
              <div>
                <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-1.5">Import Sales Channel</label>
                <input name="salesChannel" value={settings.salesChannel} onChange={handleChange} className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl text-sm outline-none" />
              </div>
              <div className="col-span-2">
                <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-1.5">OAuth 2.0 Bearer Token</label>
                <input type="password" name="token" value={settings.token} onChange={handleChange} className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl text-sm outline-none" />
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-8">
        <h3 className="text-sm font-bold text-[#002D72] uppercase tracking-widest border-l-4 border-[#002D72] pl-3 mb-8">Business Rule Configuration</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-12">
          {renderListManager('Inventory Endpoints', 'stockEndpoints', newEndpoint, setNewEndpoint, 'e.g. Store_01')}
          {renderListManager('Order Sales Channels', 'orderSalesChannels', newOrderChannel, setNewOrderChannel, 'e.g. TikTok_ES')}
          {renderListManager('Available Rulesets', 'rulesets', newRuleset, setNewRuleset, 'e.g. standard_ffs')}

          <div className="space-y-4">
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest">Delivery Countries</label>
            <div className="flex gap-2">
              <input 
                value={newCountryCode} 
                onChange={(e) => setNewCountryCode(e.target.value.toUpperCase())} 
                className="w-16 px-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none" 
                placeholder="FR"
                maxLength={2}
              />
              <input 
                value={newCountryName} 
                onChange={(e) => setNewCountryName(e.target.value)} 
                className="flex-1 px-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none" 
                placeholder="France"
              />
              <button 
                onClick={addCountry}
                className="px-4 py-2 bg-onestock-blue text-white font-bold text-xs rounded-lg hover:bg-[#001F4D]"
              >
                Add
              </button>
            </div>
            <div className="flex flex-wrap gap-2">
              {settings.deliveryCountries.map(c => (
                <div key={c.code} className="bg-blue-50 border border-blue-100 px-3 py-1.5 rounded-lg flex items-center gap-2">
                  <span className="text-xs font-mono font-bold text-onestock-blue">{c.code}</span>
                  <span className="text-[10px] text-gray-500">{c.name}</span>
                  <button onClick={() => removeCountry(c.code)} className="text-blue-300 hover:text-red-500">
                    <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
                </div>
              ))}
            </div>
