import { Product, AppSettings } from '../types';

export interface OrderGenerationRequest {
  type: 'sfs' | 'ckc' | 'ropis';
  count: number;
  productsPerOrder: number;
  countryCode?: string;
  salesChannel?: string;
  parentOrderId: string;
  orderIdPrefix: string;
  startIndex: number;
}

const FIRST_NAMES = ["Jean", "Marie", "William", "Elena", "Lucas", "Sophie", "Inès", "Pablo", "Oliver", "Amelia"];
const LAST_NAMES = ["Dupont", "Smith", "Garcia", "Rossi", "Müller", "Lefebvre", "Martinez", "Taylor", "King", "Of Cambridge"];
const CITIES: Record<string, { city: string; zip: string; lines: string[] }[]> = {
  FR: [
    { city: "Toulouse", zip: "31400", lines: ["8 Rue des Trente-Six Ponts"] },
    { city: "Paris", zip: "75001", lines: ["1 Rue de Rivoli"] },
    { city: "Lyon", zip: "69002", lines: ["12 Place Bellecour"] }
  ],
  GB: [
    { city: "London", zip: "W1U 1EE", lines: ["10-12 James St", "1 Buckingham Palace"] },
    { city: "Manchester", zip: "M1 1AG", lines: ["1 Piccadilly Gardens"] }
  ],
  ES: [
    { city: "Madrid", zip: "28001", lines: ["Calle de Serrano, 1"] },
    { city: "Barcelona", zip: "08001", lines: ["La Rambla, 10"] }
  ]
};

const getRandom = <T>(arr: T[]): T => arr[Math.floor(Math.random() * arr.length)];

export const generateOrderPayloads = (
  request: OrderGenerationRequest,
  availableProducts: Product[],
  settings: AppSettings
) => {
  const { siteId, token } = settings;
  const now = Math.floor(Date.now() / 1000);
  const parentId = request.parentOrderId;

  const orders: any[] = [];
  let totalParentPrice = 0;
  const currency = availableProducts[0]?.currency || "EUR";

  for (let i = 0; i < request.count; i++) {
    const firstName = getRandom(FIRST_NAMES);
    const lastName = getRandom(LAST_NAMES);
    const email = `${firstName.toLowerCase()}.${lastName.toLowerCase().replace(' ', '')}@onestock-retail.com`;
    const phone = `0${Math.floor(100000000 + Math.random() * 900000000)}`;

    const countryCode = request.countryCode || getRandom(settings.deliveryCountries).code;
    const addressData = getRandom(CITIES[countryCode] || CITIES.FR);
    const salesChannel = request.salesChannel || getRandom(settings.orderSalesChannels);

    let orderPrice = 0;
    const shuffled = [...availableProducts].sort(() => 0.5 - Math.random());
    const selected = shuffled.slice(0, Math.min(request.productsPerOrder, availableProducts.length));

    const orderItems = selected.map(p => {
      const price = parseFloat(p.price) || 0;
      orderPrice += price;
      return {
        item_id: p.sku,
        quantity: 1,
        pricing_details: {
          original_price: price,
          price: price,
          original_unit_price: price,
          unit_price: price
        },
        information: {
          virtual: false,
          lot: ""
        }
      };
    });

    totalParentPrice += orderPrice;

    // Order ID follows Pattern + Padded Counter
    const currentIndex = request.startIndex + i;
    const counter = currentIndex.toString().padStart(8, '0');
    const orderId = `${request.orderIdPrefix}${counter}`;

    const types = request.type === 'sfs' ? ['ffs'] : request.type === 'ckc' ? ['ffs', 'ckc'] : ['ropis'];

    const orderPayload = {
      site_id: siteId,
      token: token,
      parent_order_id: parentId,
      order: {
        id: orderId,
        types: types,
        sales_channel: salesChannel,
        original_ruleset_id: getRandom(settings.rulesets),
        date: now,
        on_available_stock: { auto_orchestrable: true },
        customer: {
          email,
          first_name: firstName,
          last_name: lastName,
          phone_number: phone,
          title: getRandom(['M.', 'Mme', 'Sir', ''])
        },
        delivery: {
          destination: {
            address: {
              city: addressData.city,
              zip_code: addressData.zip,
              lines: addressData.lines,
              regions: { country: { code: countryCode } },
              contact: {
                first_name: firstName,
                last_name: lastName,
                email,
                phone_number: phone
              }
            },
            ...(request.type !== 'sfs' ? { endpoint_id: getRandom(settings.stockEndpoints) } : {})
          },
          carrier: { name: "mock" }
        },
        pricing_details: {
          currency,
          price: orderPrice,
          original_price: orderPrice,
          price_including_tax: orderPrice,
          price_excluding_tax: parseFloat((orderPrice * 0.8).toFixed(2)),
          address: {
            city: addressData.city,
            zip_code: addressData.zip,
            lines: addressData.lines,
            regions: { country: { code: countryCode } },
            contact: { first_name: firstName, last_name: lastName, email, phone_number: phone }
          }
        },
        order_items: orderItems,
        shipping_fees: [{ currency, original_price: 0, price: 0 }]
      }
    };

    orders.push(orderPayload);
  }

  const parentOrderPayload = {
    site_id: siteId,
    token: token,
    parent_order: {
      id: parentId,
      pricing_details: {
        price: parseFloat(totalParentPrice.toFixed(2)),
        currency
      }
    }
  };

  return {
    parent: parentOrderPayload,
    subOrders: orders
  };
};

