import React, { useState, useEffect } from 'react';
import { Product, AppSettings } from '../types';
import { generateOrderPayloads, OrderGenerationRequest } from '../services/orderService';

interface StepOrderGenerationProps {
  products: Product[];
  settings: AppSettings;
  onCancel: () => void;
}

const StepOrderGeneration: React.FC<StepOrderGenerationProps> = ({ products, settings, onCancel }) => {
  const [request, setRequest] = useState<OrderGenerationRequest>({
    type: 'sfs',
    count: 3,
    productsPerOrder: 2,
    countryCode: settings.deliveryCountries[0]?.code || 'FR',
    salesChannel: settings.orderSalesChannels[0] || '',
    parentOrderId: 'PORD-20260001',
    orderIdPrefix: 'SFS-',
    startIndex: 1
  });

  // Sync prefix with strategy type when strategy changes
  const handleStrategyChange = (t: 'sfs' | 'ckc' | 'ropis') => {
    setRequest(prev => ({ 
      ...prev, 
      type: t,
      orderIdPrefix: `${t.toUpperCase()}-`
    }));
  };

  const [generatedData, setGeneratedData] = useState<{ parent: any, subOrders: any[] } | null>(null);
  const [copyStatus, setCopyStatus] = useState<string | null>(null);

  const handleGenerate = () => {
    if (products.length === 0) {
      alert("No products available to generate orders.");
      return;
    }
    const data = generateOrderPayloads(request, products, settings);
    setGeneratedData(data);
  };

  const handleCopy = (content: any, label: string) => {
    navigator.clipboard.writeText(JSON.stringify(content, null, 4));
    setCopyStatus(label);
    setTimeout(() => setCopyStatus(null), 2000);
  };

  const handleDownloadAll = () => {
    if (!generatedData) return;
    const combined = {
      parent_order: generatedData.parent,
      sub_orders: generatedData.subOrders
    };
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(combined, null, 4));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", `onestock_orders_package_${Date.now()}.json`);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500 pb-20">
      <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-8">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-8">
          <div>
            <h2 className="text-2xl font-bold text-[#002D72]">Customer Order Generation</h2>
            <p className="text-sm text-gray-500 mt-1">Simulate real customer traffic using {products.length} imported articles.</p>
          </div>
          <div className="flex gap-3">
            <button onClick={onCancel} className="px-4 py-2 text-sm font-semibold text-gray-600 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors">Cancel</button>
            <button 
              onClick={handleGenerate}
              className="px-6 py-2 bg-[#002D72] text-white font-bold rounded-lg hover:bg-[#001F4D] shadow-lg flex items-center gap-2 transition-all text-sm"
            >
              Generate New Batch
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.5 14.25v-2.625a3.375 3.375 0 00-3.375-3.375h-1.5A1.125 1.125 0 0113.5 7.125v-1.5a3.375 3.375 0 00-3.375-3.375H8.25m3.75 9v6m3-3H9m1.5-12H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 00-9-9z" /></svg>
            </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 p-6 bg-gray-50 rounded-xl border border-gray-100">
          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Order Strategy</label>
            <div className="grid grid-cols-3 gap-2">
              {(['sfs', 'ckc', 'ropis'] as const).map(t => (
                <button 
                  key={t}
                  onClick={() => handleStrategyChange(t)}
                  className={`py-2 text-[10px] font-bold rounded-lg uppercase tracking-wider transition-all border ${
                    request.type === t ? 'bg-[#002D72] border-[#002D72] text-white' : 'bg-white border-gray-200 text-gray-400 hover:border-blue-200'
                  }`}
                >
                  {t}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Destination Country</label>
            <select 
              value={request.countryCode}
              onChange={e => setRequest(prev => ({ ...prev, countryCode: e.target.value }))}
              className="w-full px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-bold text-onestock-blue outline-none focus:border-onestock-blue"
            >
              {settings.deliveryCountries.map(c => (
                <option key={c.code} value={c.code}>{c.name} ({c.code})</option>
              ))}
              {settings.deliveryCountries.length === 0 && <option value="">No countries configured</option>}
            </select>
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Sales Channel</label>
            <select 
              value={request.salesChannel}
              onChange={e => setRequest(prev => ({ ...prev, salesChannel: e.target.value }))}
              className="w-full px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-bold text-onestock-blue outline-none focus:border-onestock-blue"
            >
              {settings.orderSalesChannels.map(sc => (
                <option key={sc} value={sc}>{sc}</option>
              ))}
              {settings.orderSalesChannels.length === 0 && <option value="">No channels configured</option>}
            </select>
          </div>

          <div className="col-span-1 md:col-span-2 lg:col-span-1">
             <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Parent Order ID (Modifiable)</label>
             <input 
               type="text"
               value={request.parentOrderId}
               onChange={e => setRequest(prev => ({ ...prev, parentOrderId: e.target.value }))}
               className="w-full px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-mono font-bold text-onestock-blue outline-none focus:border-onestock-blue border-l-4 border-l-onestock-blue shadow-sm"
               placeholder="PORD-20260000"
             />
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Order ID Prefix</label>
            <input 
              type="text"
              value={request.orderIdPrefix}
              onChange={e => setRequest(prev => ({ ...prev, orderIdPrefix: e.target.value }))}
              className="w-full px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-mono font-bold text-onestock-blue outline-none focus:border-onestock-blue"
              placeholder="SFS-"
            />
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Start Counter at</label>
            <input 
              type="number" min="0"
              value={request.startIndex}
              onChange={e => setRequest(prev => ({ ...prev, startIndex: parseInt(e.target.value) || 0 }))}
              className="w-full px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-mono font-bold text-onestock-blue outline-none focus:border-onestock-blue"
            />
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Batch Order Count</label>
            <input 
              type="number" min="1" max="50"
              value={request.count}
              onChange={e => setRequest(prev => ({ ...prev, count: parseInt(e.target.value) || 1 }))}
              className="w-full px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-bold text-onestock-blue"
            />
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Items per Order</label>
            <input 
              type="number" min="1" max="10"
              value={request.productsPerOrder}
              onChange={e => setRequest(prev => ({ ...prev, productsPerOrder: parseInt(e.target.value) || 1 }))}
              className="w-full px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-bold text-onestock-blue"
            />
          </div>

          <div className="flex items-end">
            <div className="w-full p-2 bg-blue-50/50 rounded-lg border border-blue-100 flex items-center gap-2">
              <svg className="w-4 h-4 text-onestock-blue" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
              <span className="text-[10px] text-onestock-blue font-medium">Preview Sub-ID: <strong className="uppercase">{request.orderIdPrefix}{request.startIndex.toString().padStart(8, '0')}</strong></span>
            </div>
          </div>
        </div>
      </div>

      {generatedData && (
        <div className="space-y-6 animate-in fade-in slide-in-from-top-4">
          <div className="flex items-center justify-between">
            <h3 className="text-lg font-bold text-[#002D72] flex items-center gap-2">
              Generated JSON Package
              <span className="text-xs font-medium px-2 py-0.5 bg-blue-100 text-blue-700 rounded-full">
                1 Parent + {generatedData.subOrders.length} Sub-Orders
              </span>
            </h3>
            <button 
              onClick={handleDownloadAll}
              className="px-4 py-2 text-xs font-bold text-onestock-blue border border-onestock-blue rounded-lg hover:bg-blue-50 transition-all flex items-center gap-2"
            >
              Download Full Package (.json)
            </button>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="space-y-4">
              <div className="bg-[#001F4D] rounded-xl overflow-hidden shadow-xl border border-white/10">
                <div className="px-4 py-2 bg-white/5 border-b border-white/10 flex justify-between items-center">
                  <span className="text-[10px] font-bold text-blue-300 uppercase tracking-widest">Parent Order Payload</span>
                  <button 
                    onClick={() => handleCopy(generatedData.parent, 'parent')}
                    className="text-[10px] font-bold text-white/40 hover:text-white transition-colors"
                  >
                    {copyStatus === 'parent' ? 'COPIED!' : 'COPY'}
                  </button>
                </div>
                <div className="p-4 overflow-y-auto max-h-48 text-[11px] font-mono text-blue-100">
                  <pre>{JSON.stringify(generatedData.parent, null, 2)}</pre>
                </div>
              </div>

              {generatedData.subOrders.slice(0, 1).map((order, idx) => (
                <div key={idx} className="bg-[#001F4D] rounded-xl overflow-hidden shadow-xl border border-white/10">
                  <div className="px-4 py-2 bg-white/5 border-b border-white/10 flex justify-between items-center">
                    <span className="text-[10px] font-bold text-blue-300 uppercase tracking-widest">Example Sub-Order (1/{generatedData.subOrders.length})</span>
                    <button 
                      onClick={() => handleCopy(order, `sub-${idx}`)}
                      className="text-[10px] font-bold text-white/40 hover:text-white transition-colors"
                    >
                      {copyStatus === `sub-${idx}` ? 'COPIED!' : 'COPY'}
                    </button>
                  </div>
                  <div className="p-4 overflow-y-auto max-h-96 text-[11px] font-mono text-blue-100">
                    <pre>{JSON.stringify(order, null, 2)}</pre>
                  </div>
                </div>
              ))}
            </div>

            <div className="space-y-4">
              <div className="bg-white rounded-xl border border-gray-200 p-6 shadow-sm">
                <h4 className="text-xs font-bold text-[#002D72] uppercase tracking-widest mb-4">Simulation Summary</h4>
                <div className="space-y-4">
                  <div className="flex justify-between items-center py-2 border-b border-gray-50">
                    <span className="text-xs text-gray-400 uppercase font-bold tracking-tighter">Parent ID</span>
                    <span className="text-sm font-mono font-bold text-onestock-blue">{request.parentOrderId}</span>
                  </div>
                  <div className="flex justify-between items-center py-2 border-b border-gray-50">
                    <span className="text-xs text-gray-400 uppercase font-bold tracking-tighter">Country Code</span>
                    <span className="text-sm font-bold text-onestock-blue">{request.countryCode}</span>
                  </div>
                  <div className="flex justify-between items-center py-2 border-b border-gray-50">
                    <span className="text-xs text-gray-400 uppercase font-bold tracking-tighter">Sales Channel</span>
                    <span className="text-sm font-bold text-onestock-blue">{request.salesChannel}</span>
                  </div>
                  <div className="flex justify-between items-center py-2 border-b border-gray-50">
                    <span className="text-xs text-gray-400 uppercase font-bold tracking-tighter">ID Range</span>
                    <span className="text-[10px] bg-blue-100 text-blue-700 px-2 py-0.5 rounded-full font-bold uppercase tracking-wider">
                      {request.orderIdPrefix}{request.startIndex.toString().padStart(8, '0')} ...
                    </span>
                  </div>
                </div>

                <div className="mt-8 p-4 bg-green-50 rounded-lg border border-green-100 flex items-start gap-3">
                  <svg className="w-5 h-5 text-green-600 shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                  <p className="text-[11px] text-green-800 leading-relaxed">
                    <strong>Customization applied:</strong> Payloads now use your manual IDs and prefixes. You can iterate through batches by incrementing the start counter.
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default StepOrderGeneration;

