const LAST_NAMES = ["Dupont", "Smith", "Garcia", "Rossi", "Müller", "Lefebvre", "Martinez", "Taylor", "King", "Of Cambridge"];
const CITIES: Record<string, { city: string; zip: string; lines: string[] }[]> = {
  FR: [
    { city: "Toulouse", zip: "31400", lines: ["8 Rue des Trente-Six Ponts"] },
    { city: "Paris", zip: "75001", lines: ["1 Rue de Rivoli"] },
    { city: "Lyon", zip: "69002", lines: ["12 Place Bellecour"] }
  ],
