const DEFAULT_DATA = COUNTRY_DATA.FR;

const getRandom = <T>(arr: T[]): T => arr[Math.floor(Math.random() * arr.length)];

export const generateOrderPayloads = (
  request: OrderGenerationRequest,
  availableProducts: Product[],
  settings: AppSettings
) => {
  const { siteId, token } = settings;
  const now = Math.floor(Date.now() / 1000);
  const oneDay = 86400;
  const parentId = request.parentOrderId;

  const countryCode = request.countryCode || 'FR';
  const localData = COUNTRY_DATA[countryCode] || DEFAULT_DATA;

  const orders: any[] = [];
  let totalParentPrice = 0;
  const currency = availableProducts[0]?.currency || "EUR";

  for (let i = 0; i < request.count; i++) {
    const firstName = getRandom(localData.firstNames);
    const lastName = getRandom(localData.lastNames);
    const email = `${firstName.toLowerCase()}.${lastName.toLowerCase().replace(' ', '')}@onestock-retail.com`;
    const phone = countryCode === 'GB' ? `+44 ${Math.floor(7000000000 + Math.random() * 900000000)}` : 
                 countryCode === 'ES' ? `+34 ${Math.floor(600000000 + Math.random() * 90000000)}` :
                 `+33 ${Math.floor(600000000 + Math.random() * 90000000)}`;

    const addressData = getRandom(localData.addresses);
    const salesChannel = request.salesChannel || getRandom(settings.orderSalesChannels);

    let subtotal = 0;
    const shuffled = [...availableProducts].sort(() => 0.5 - Math.random());
    const selected = shuffled.slice(0, Math.min(request.productsPerOrder, availableProducts.length));

    const orderItems = selected.map(p => {
      const price = parseFloat(p.price) || 0;
      subtotal += price;
      return {
        item_id: p.sku,
        quantity: 1,
        pricing_details: {
          currency: p.currency || currency,
          original_price: price,
          price: price,
          original_unit_price: price,
          unit_price: price
        },
        information: {
          virtual: false,
          lot: `Lot : ${Math.floor(Math.random() * 10000000000)}`
        }
      };
    });

    const shippingPrice = request.type === 'sfs' ? 10 : 0;
    const totalPrice = parseFloat((subtotal + shippingPrice).toFixed(2));
    totalParentPrice += totalPrice;

    const currentIndex = request.startIndex + i;
    const counter = currentIndex.toString().padStart(8, '0');
    const orderId = `${request.orderIdPrefix}${counter}`;

    let orderTypes: string[] = [];
    if (request.type === 'sfs') orderTypes = ['ffs'];
    else if (request.type === 'ckc') orderTypes = ['ffs', 'ckc'];
    else orderTypes = ['ropis'];

    const orderPayload = {
      site_id: siteId,
      token: token,
      parent_order_id: parentId,
      order: {
        id: orderId,
        types: orderTypes,
        sales_channel: salesChannel,
        reservation_rank: "01",
        on_available_stock: { auto_orchestrable: true },
        date: now,
        information: {
          amount_to_capture: `${totalPrice} ${currency}`,
          captured_amount: `${totalPrice} ${currency}`,
          amount_to_be_refunded: `0 ${currency}`,
          amount_refunded: `0 ${currency}`
        },
        delivery: {
          destination: {
            address: {
              city: addressData.city,
              zip_code: addressData.zip,
              lines: addressData.lines,
              regions: { country: { code: countryCode } },
              contact: {
                title: getRandom(['M.', 'Mme', '']),
                first_name: firstName,
                last_name: lastName,
                email,
                phone_number: phone
              }
            },
            ...(request.type !== 'sfs' ? { endpoint_id: getRandom(settings.stockEndpoints) } : {})
          },
          carrier: { name: "mock" }
        },
        delivery_promise: {
          original_delivery_option: {
            carbon_footprint: 100,
            cost: shippingPrice,
            cutoff: now + oneDay,
            delivery_method: request.type === 'sfs' ? "standard" : "collect",
            destination: {
              location: {
                country: countryCode,
                zip_code: addressData.zip
              }
            },
            eta_start: now + oneDay,
            eta_end: now + (oneDay * 2),
            shipment_number: 1,
            status: "valid"
          },
          sent_delivery_option: {
            eta_start: now + oneDay,
            eta_end: now + (oneDay * 2)
          }
        },
        customer: {
          email,
          first_name: firstName,
          last_name: lastName,
          phone_number: phone,
          title: getRandom(['M.', 'Mme', ''])
        },
        pricing_details: {
          currency,
          original_price: totalPrice,
          price: totalPrice,
          price_including_tax: totalPrice,
          price_excluding_tax: parseFloat((totalPrice * 0.8).toFixed(2)),
          taxes: [
            {
              amount: parseFloat((totalPrice * 0.2).toFixed(2)),
              included_in_price: true
            }
          ],
          address: {
            city: addressData.city,
            zip_code: addressData.zip,
            lines: addressData.lines,
            regions: { country: { code: countryCode } },
            contact: {
              title: "",
              first_name: firstName,
              last_name: lastName,
              email,
              phone_number: phone
            }
          }
        },
        order_items: orderItems,
        shipping_fees: [
          {
            currency,
            original_price: shippingPrice,
            price: shippingPrice
          }
        ]
      }
    };

    orders.push(orderPayload);
  }

  const parentOrderPayload = {
    site_id: siteId,
    token: token,
    parent_order: {
      id: parentId,
      pricing_details: {
        price: parseFloat(totalParentPrice.toFixed(2)),
        currency
      }
    }
  };

  return {
    parent: parentOrderPayload,
    subOrders: orders
  };
};

import React, { useState } from 'react';
import { Product, AppSettings } from '../types';
