const DEFAULT_DATA = COUNTRY_DATA.FR;

const getRandom = <T>(arr: T[]): T => arr[Math.floor(Math.random() * arr.length)];

export const generateOrderPayloads = (
  request: OrderGenerationRequest,
  availableProducts: Product[],
  settings: AppSettings
) => {
  const { siteId, token } = settings;
  const now = Math.floor(Date.now() / 1000);
  const oneDay = 86400;
  // This value comes directly from the UI input "Parent Order ID"
  const parentIdValue = request.parentOrderId;

  const countryCode = request.countryCode || 'FR';
  const localData = COUNTRY_DATA[countryCode] || DEFAULT_DATA;

  const orders: any[] = [];
  let totalParentPrice = 0;
  const currency = availableProducts[0]?.currency || "EUR";

  for (let i = 0; i < request.count; i++) {
    const firstName = getRandom(localData.firstNames);
    const lastName = getRandom(localData.lastNames);
    const email = `${firstName.toLowerCase()}.${lastName.toLowerCase().replace(' ', '')}@onestock-retail.com`;
    const phone = countryCode === 'GB' ? `+44 ${Math.floor(7000000000 + Math.random() * 900000000)}` : 
                 countryCode === 'ES' ? `+34 ${Math.floor(600000000 + Math.random() * 90000000)}` :
                 `+33 ${Math.floor(600000000 + Math.random() * 90000000)}`;

    const addressData = getRandom(localData.addresses);
    const salesChannel = request.salesChannel || getRandom(settings.orderSalesChannels);

    let subtotal = 0;
    const shuffled = [...availableProducts].sort(() => 0.5 - Math.random());
    const selected = shuffled.slice(0, Math.min(request.productsPerOrder, availableProducts.length));

    const orderItems = selected.map(p => {
      const price = parseFloat(p.price) || 0;
      subtotal += price;
      return {
        item_id: p.sku,
        quantity: 1,
        pricing_details: {
          currency: p.currency || currency,
          original_price: price,
          price: price,
          original_unit_price: price,
          unit_price: price
        },
        information: {
          virtual: false,
          lot: `Lot : ${Math.floor(Math.random() * 10000000000)}`
        }
      };
    });

    const shippingPrice = request.type === 'sfs' ? 10 : 0;
    const totalPrice = parseFloat((subtotal + shippingPrice).toFixed(2));
    totalParentPrice += totalPrice;

    const currentIndex = request.startIndex + i;
    const counter = currentIndex.toString().padStart(8, '0');
    const orderId = `${request.orderIdPrefix}${counter}`;

    let orderTypes: string[] = [];
    if (request.type === 'sfs') orderTypes = ['ffs'];
    else if (request.type === 'ckc') orderTypes = ['ffs', 'ckc'];
    else orderTypes = ['ropis'];

    const orderPayload = {
      site_id: siteId,
      token: token,
      // parent_order_id takes the value of the Parent Order ID field from the UI
      parent_order_id: parentIdValue,
      order: {
        id: orderId,
        types: orderTypes,
        sales_channel: salesChannel,
        reservation_rank: "01",
        on_available_stock: { auto_orchestrable: true },
        date: now,
        information: {
          amount_to_capture: `${totalPrice} ${currency}`,
          captured_amount: `${totalPrice} ${currency}`,
          amount_to_be_refunded: `0 ${currency}`,
          amount_refunded: `0 ${currency}`
        },
        delivery: {
          destination: {
            address: {
              city: addressData.city,
              zip_code: addressData.zip,
              lines: addressData.lines,
              regions: { country: { code: countryCode } },
              contact: {
                title: getRandom(['M.', 'Mme', '']),
                first_name: firstName,
                last_name: lastName,
                email,
                phone_number: phone
              }
            },
            ...(request.type !== 'sfs' ? { endpoint_id: getRandom(settings.stockEndpoints) } : {})
          },
          carrier: { name: "mock" }
        },
        delivery_promise: {
          original_delivery_option: {
            carbon_footprint: 100,
            cost: shippingPrice,
            cutoff: now + oneDay,
            delivery_method: request.type === 'sfs' ? "standard" : "collect",
            destination: {
              location: {
                country: countryCode,
                zip_code: addressData.zip
              }
            },
            eta_start: now + oneDay,
            eta_end: now + (oneDay * 2),
            shipment_number: 1,
            status: "valid"
          },
          sent_delivery_option: {
            eta_start: now + oneDay,
            eta_end: now + (oneDay * 2)
          }
        },
        customer: {
          email,
          first_name: firstName,
          last_name: lastName,
          phone_number: phone,
          title: getRandom(['M.', 'Mme', ''])
        },
        pricing_details: {
          currency,
          original_price: totalPrice,
          price: totalPrice,
          price_including_tax: totalPrice,
          price_excluding_tax: parseFloat((totalPrice * 0.8).toFixed(2)),
          taxes: [
            {
              amount: parseFloat((totalPrice * 0.2).toFixed(2)),
              included_in_price: true
            }
          ],
          address: {
            city: addressData.city,
            zip_code: addressData.zip,
            lines: addressData.lines,
            regions: { country: { code: countryCode } },
            contact: {
              title: "",
              first_name: firstName,
              last_name: lastName,
              email,
              phone_number: phone
            }
          }
        },
        order_items: orderItems,
        shipping_fees: [
          {
            currency,
            original_price: shippingPrice,
            price: shippingPrice
          }
        ]
      }
    };

    orders.push(orderPayload);
  }

  const parentOrderPayload = {
    site_id: siteId,
    token: token,
    parent_order: {
      id: parentIdValue, // Consistent with the value used in sub-orders
      pricing_details: {
        price: parseFloat(totalParentPrice.toFixed(2)),
        currency
      }
    }
  };

  return {
    parent: parentOrderPayload,
    subOrders: orders
  };
};

import React, { useState } from 'react';
import { Product, AppSettings } from '../types';
import { generateOrderPayloads, OrderGenerationRequest } from '../services/orderService';
import JSZip from 'https://esm.sh/jszip';

interface StepOrderGenerationProps {
  products: Product[];
  settings: AppSettings;
  onCancel: () => void;
}

const StepOrderGeneration: React.FC<StepOrderGenerationProps> = ({ products, settings, onCancel }) => {
  const [request, setRequest] = useState<OrderGenerationRequest>({
    type: 'sfs',
    count: 3,
    productsPerOrder: 2,
    countryCode: settings.deliveryCountries[0]?.code || 'FR',
    salesChannel: settings.orderSalesChannels[0] || '',
    parentOrderId: '202509000001', // Default value updated as requested
    orderIdPrefix: 'SFS-',
    startIndex: 1
  });

  const [generatedData, setGeneratedData] = useState<{ parent: any, subOrders: any[] } | null>(null);
  const [copyStatus, setCopyStatus] = useState<string | null>(null);
  const [isZipping, setIsZipping] = useState(false);

  const handleStrategyChange = (t: 'sfs' | 'ckc' | 'ropis') => {
    setRequest(prev => ({ 
      ...prev, 
      type: t,
      orderIdPrefix: `${t.toUpperCase()}-`
    }));
  };

  const handleGenerate = () => {
    if (products.length === 0) {
      alert("No products available to generate orders.");
      return;
    }
    const data = generateOrderPayloads(request, products, settings);
    setGeneratedData(data);
  };

  const handleCopy = (content: any, label: string) => {
    navigator.clipboard.writeText(JSON.stringify(content, null, 4));
    setCopyStatus(label);
    setTimeout(() => setCopyStatus(null), 2000);
  };

  const handleDownloadZip = async () => {
    if (!generatedData) return;
    setIsZipping(true);
    try {
      const zip = new JSZip();

      // Add parent order
      zip.file("parent_order.json", JSON.stringify(generatedData.parent, null, 4));

      // Add sub orders
      const ordersFolder = zip.folder("orders");
      generatedData.subOrders.forEach((order) => {
        const orderId = order.order.id;
        ordersFolder?.file(`${orderId}.json`, JSON.stringify(order, null, 4));
      });

      const content = await zip.generateAsync({ type: "blob" });
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", URL.createObjectURL(content));
      downloadAnchorNode.setAttribute("download", `onestock_orders_package_${Date.now()}.zip`);
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
    } catch (err) {
      console.error(err);
      alert("Failed to generate ZIP archive.");
    } finally {
      setIsZipping(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500 pb-20">
      <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-8">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-8">
          <div>
            <h2 className="text-2xl font-bold text-[#002D72]">Customer Order Generation</h2>
            <p className="text-sm text-gray-500 mt-1">Simulate real customer traffic using localized name and address datasets.</p>
          </div>
          <div className="flex gap-3">
            <button onClick={onCancel} className="px-4 py-2 text-sm font-semibold text-gray-600 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors">Cancel</button>
            <button 
              onClick={handleGenerate}
              className="px-6 py-2 bg-[#002D72] text-white font-bold rounded-lg hover:bg-[#001F4D] shadow-lg flex items-center gap-2 transition-all text-sm"
            >
              Generate New Batch
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.5 14.25v-2.625a3.375 3.375 0 00-3.375-3.375h-1.5A1.125 1.125 0 0113.5 7.125v-1.5a3.375 3.375 0 00-3.375-3.375H8.25m3.75 9v6m3-3H9m1.5-12H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 00-9-9z" /></svg>
            </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 p-6 bg-gray-50 rounded-xl border border-gray-100">
          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Order Strategy</label>
            <div className="grid grid-cols-3 gap-2">
              {(['sfs', 'ckc', 'ropis'] as const).map(t => (
                <button 
                  key={t}
                  onClick={() => handleStrategyChange(t)}
                  className={`py-2 text-[10px] font-bold rounded-lg uppercase tracking-wider transition-all border ${
                    request.type === t ? 'bg-[#002D72] border-[#002D72] text-white' : 'bg-white border-gray-200 text-gray-400 hover:border-blue-200'
                  }`}
                >
                  {t}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Destination Country</label>
            <select 
              value={request.countryCode}
              onChange={e => setRequest(prev => ({ ...prev, countryCode: e.target.value }))}
              className="w-full px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-bold text-onestock-blue outline-none focus:border-onestock-blue"
            >
              {settings.deliveryCountries.map(c => (
                <option key={c.code} value={c.code}>{c.name} ({c.code})</option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Sales Channel</label>
            <select 
              value={request.salesChannel}
              onChange={e => setRequest(prev => ({ ...prev, salesChannel: e.target.value }))}
              className="w-full px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-bold text-onestock-blue outline-none focus:border-onestock-blue"
            >
              {settings.orderSalesChannels.map(sc => (
                <option key={sc} value={sc}>{sc}</option>
              ))}
