import { GoogleGenAI, Type } from "@google/genai";
import { Product } from "../types";

export interface CustomerIdentity {
  firstName: string;
  lastName: string;
  title: string;
  address: {
    city: string;
    zip_code: string;
    lines: string[];
  };
  phone: string;
}

export const generateAIIdentities = async (countryCode: string, count: number): Promise<CustomerIdentity[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Generate ${count} highly realistic and diverse customer identities for the country: ${countryCode}. 
  Include:
  - Common first and last names for that specific culture.
  - Authentic titles (e.g., M., Mme for FR; Mr., Ms., Dr. for GB; Sr., Sra. for ES).
  - Valid address structures for ${countryCode} (real cities, existing zip code formats, realistic street names).
  - Realistic phone numbers with the correct country prefix.

  Return as a JSON object with an "identities" array.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            identities: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  firstName: { type: Type.STRING },
                  lastName: { type: Type.STRING },
                  title: { type: Type.STRING },
                  address: {
                    type: Type.OBJECT,
                    properties: {
                      city: { type: Type.STRING },
                      zip_code: { type: Type.STRING },
                      lines: { type: Type.ARRAY, items: { type: Type.STRING } }
                    },
                    required: ["city", "zip_code", "lines"]
                  },
                  phone: { type: Type.STRING }
                },
                required: ["firstName", "lastName", "address", "phone"]
              }
            }
          }
        }
      }
    });

    const data = JSON.parse(response.text.trim());
    return data.identities || [];
  } catch (error) {
    console.error("Identity generation error:", error);
    return [];
  }
};

export const scanWebsiteForProducts = async (url: string, limit: number): Promise<Product[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const productTarget = Math.max(1, Math.ceil(limit / 3));

  const prompt = `Analyze the following URL to extract detailed product data: ${url}. 
  MISSION: Extract at least ${productTarget} different products from the page to help reach a total target of ${limit} unique SKUs (variants).
  Identify Mother ID (product_id) and all variant information (sizes).

  RETURN A STRICT JSON structure:
  { 
    "products": [ 
      { 
        "base_sku": "...", 
        "name": "...", 
        "description": "...", 
        "price": "...", 
        "compare_price": "...",
        "currency": "...",
        "color": "...", 
        "category": "...",
        "department": "...",
        "subdepartment": "...",
        "sizes": ["...", "..."], 
        "images": ["...", "..."]
      } 
    ] 
  }`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            products: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  base_sku: { type: Type.STRING },
                  name: { type: Type.STRING },
                  description: { type: Type.STRING },
                  price: { type: Type.STRING },
                  compare_price: { type: Type.STRING },
                  currency: { type: Type.STRING },
                  color: { type: Type.STRING },
                  category: { type: Type.STRING },
                  department: { type: Type.STRING },
                  subdepartment: { type: Type.STRING },
                  sizes: { type: Type.ARRAY, items: { type: Type.STRING } },
                  images: { type: Type.ARRAY, items: { type: Type.STRING } }
                },
                required: ["base_sku", "name", "price", "sizes", "images"]
              }
            }
          }
        }
      }
    });

    const data = JSON.parse(response.text.trim());
    const rawProducts = data.products || [];
    const flattenedProducts: Product[] = [];

    for (const p of rawProducts) {
      if (flattenedProducts.length >= limit) break;
      const allSizes = p.sizes && p.sizes.length > 0 ? p.sizes : ["Unique"];
      const motherId = p.base_sku || `ID-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;

      for (let index = 0; index < allSizes.length; index++) {
        if (flattenedProducts.length >= limit) break;
        const size = allSizes[index];
        const sizeSlug = size.replace(/[^a-zA-Z0-9]/g, '');
        const uniqueSku = `${motherId}-${sizeSlug || index}`;
        const mainImg = p.images?.[0] || '';

        flattenedProducts.push({
          id: uniqueSku, 
          sku: uniqueSku,
          parentSku: motherId,
          name: p.name,
          description: p.description || "No description",
          imageUrl: mainImg,
          productUrl: url,
          price: p.price.toString(),
          comparePrice: (p.compare_price || "0").toString(),
          currency: p.currency || "EUR",
          color: p.color || "N/A",
          size: size,
          category: p.category || "uncategorized",
          department: p.department || "Skincare",
          subdepartment: p.subdepartment || "Cleanser",
          weight: 0.4,
          length: 20,
          width: 15,
          height: 3,
          images_big: p.images || []
        });
      }
    }
    return flattenedProducts.slice(0, limit);
  } catch (error) {
    console.error("Extraction error:", error);
    return [];
  }
};

import { Product, AppSettings } from '../types';
import { CustomerIdentity } from './geminiService';

export interface OrderGenerationRequest {
  type: 'sfs' | 'ckc' | 'ropis';
  count: number;
  productsPerOrder: number;
  countryCode?: string;
  salesChannel?: string;
  parentOrderId: string;
  orderIdPrefix: string;
  startIndex: number;
}

const FALLBACK_COUNTRY_DATA: Record<string, { firstNames: string[], lastNames: string[], addresses: { city: string, zip: string, lines: string[] }[] }> = {
  FR: {
    firstNames: ["Jean", "Marie", "William", "Elena", "Lucas", "Sophie", "Inès", "Pablo", "Oliver", "Amelia", "Théo", "Léa", "Manon", "Gabriel"],
    lastNames: ["Dupont", "Lefebvre", "Martin", "Bernard", "Dubois", "Thomas", "Robert", "Richard", "Petit", "Durand"],
    addresses: [{ city: "Toulouse", zip: "31400", lines: ["8 Rue des Trente-Six Ponts"] }]
  },
  GB: {
    firstNames: ["James", "Mary", "Robert"],
    lastNames: ["Smith", "Jones", "Taylor"],
    addresses: [{ city: "London", zip: "W1U 1EE", lines: ["10-12 James St"] }]
  },
  ES: {
    firstNames: ["Antonio", "Maria", "Jose"],
    lastNames: ["Garcia", "Rodriguez", "Gonzalez"],
    addresses: [{ city: "Madrid", zip: "28001", lines: ["Calle de Serrano, 1"] }]
  }
};

const getRandom = <T>(arr: T[]): T => arr[Math.floor(Math.random() * arr.length)];

export const generateOrderPayloads = (
  request: OrderGenerationRequest,
  availableProducts: Product[],
  settings: AppSettings,
  aiIdentities?: CustomerIdentity[]
) => {
  const { siteId, token } = settings;
  const now = Math.floor(Date.now() / 1000);
  const oneDay = 86400;
  const parentIdValue = request.parentOrderId;

  const countryCode = request.countryCode || 'FR';
  const fallbackLocalData = FALLBACK_COUNTRY_DATA[countryCode] || FALLBACK_COUNTRY_DATA.FR;

  const orders: any[] = [];
  let totalParentPrice = 0;
  const currency = availableProducts[0]?.currency || "EUR";

  for (let i = 0; i < request.count; i++) {
    const aiId = aiIdentities && aiIdentities[i];

    const firstName = aiId ? aiId.firstName : getRandom(fallbackLocalData.firstNames);
    const lastName = aiId ? aiId.lastName : getRandom(fallbackLocalData.lastNames);
    const title = aiId ? aiId.title : getRandom(['M.', 'Mme', '']);
    const email = `${firstName.toLowerCase()}.${lastName.toLowerCase().replace(' ', '')}@onestock-retail.com`;
    const phone = aiId ? aiId.phone : (countryCode === 'GB' ? '+44 7123456789' : '+33 612345678');

    const addressData = aiId ? aiId.address : getRandom(fallbackLocalData.addresses);
    const salesChannel = request.salesChannel || getRandom(settings.orderSalesChannels);

    let subtotal = 0;
    const shuffled = [...availableProducts].sort(() => 0.5 - Math.random());
    const selected = shuffled.slice(0, Math.min(request.productsPerOrder, availableProducts.length));

    const orderItems = selected.map(p => {
      const price = parseFloat(p.price) || 0;
      subtotal += price;
      return {
        item_id: p.sku,
        quantity: 1,
        pricing_details: {
          currency: p.currency || currency,
          original_price: price,
          price: price,
          original_unit_price: price,
          unit_price: price
        },
        information: {
          virtual: false,
          lot: `Lot : ${Math.floor(Math.random() * 10000000000)}`
        }
      };
    });

    const shippingPrice = request.type === 'sfs' ? 10 : 0;
    const totalPrice = parseFloat((subtotal + shippingPrice).toFixed(2));
    totalParentPrice += totalPrice;

    const currentIndex = request.startIndex + i;
    const counter = currentIndex.toString().padStart(8, '0');
    const orderId = `${request.orderIdPrefix}${counter}`;

    let orderTypes: string[] = [];
    if (request.type === 'sfs') orderTypes = ['ffs'];
    else if (request.type === 'ckc') orderTypes = ['ffs', 'ckc'];
    else orderTypes = ['ropis'];

    const orderPayload = {
      site_id: siteId,
      token: token,
      parent_order_id: parentIdValue,
      order: {
        id: orderId,
        types: orderTypes,
        sales_channel: salesChannel,
        reservation_rank: "01",
        on_available_stock: { auto_orchestrable: true },
        date: now,
        information: {
          amount_to_capture: `${totalPrice} ${currency}`,
          captured_amount: `${totalPrice} ${currency}`,
          amount_to_be_refunded: `0 ${currency}`,
          amount_refunded: `0 ${currency}`
        },
        delivery: {
          destination: {
            address: {
              city: addressData.city,
              zip_code: addressData.zip_code || (addressData as any).zip,
              lines: addressData.lines,
              regions: { country: { code: countryCode } },
              contact: {
                title,
                first_name: firstName,
                last_name: lastName,
                email,
                phone_number: phone
              }
            },
            ...(request.type !== 'sfs' ? { endpoint_id: getRandom(settings.stockEndpoints) } : {})
          },
          carrier: { name: "mock" }
        },
        delivery_promise: {
          original_delivery_option: {
            carbon_footprint: 100,
            cost: shippingPrice,
            cutoff: now + oneDay,
            delivery_method: request.type === 'sfs' ? "standard" : "collect",
            destination: {
              location: {
                country: countryCode,
                zip_code: addressData.zip_code || (addressData as any).zip
              }
            },
            eta_start: now + oneDay,
            eta_end: now + (oneDay * 2),
            shipment_number: 1,
            status: "valid"
          },
          sent_delivery_option: {
            eta_start: now + oneDay,
            eta_end: now + (oneDay * 2)
          }
        },
        customer: {
          email,
          first_name: firstName,
          last_name: lastName,
          phone_number: phone,
          title
        },
        pricing_details: {
          currency,
          original_price: totalPrice,
          price: totalPrice,
          price_including_tax: totalPrice,
          price_excluding_tax: parseFloat((totalPrice * 0.8).toFixed(2)),
          taxes: [
            {
              amount: parseFloat((totalPrice * 0.2).toFixed(2)),
              included_in_price: true
            }
          ],
          address: {
            city: addressData.city,
            zip_code: addressData.zip_code || (addressData as any).zip,
            lines: addressData.lines,
            regions: { country: { code: countryCode } },
            contact: {
              title: "",
              first_name: firstName,
              last_name: lastName,
              email,
              phone_number: phone
            }
          }
        },
        order_items: orderItems,
        shipping_fees: [
          {
            currency,
            original_price: shippingPrice,
            price: shippingPrice
          }
        ]
      }
    };

    orders.push(orderPayload);
  }

  const parentOrderPayload = {
    site_id: siteId,
    token: token,
    parent_order: {
      id: parentIdValue,
      pricing_details: {
        price: parseFloat(totalParentPrice.toFixed(2)),
        currency
      }
    }
  };

  return {
    parent: parentOrderPayload,
    subOrders: orders
  };
};

import React, { useState } from 'react';
import { Product, AppSettings } from '../types';
import { generateOrderPayloads, OrderGenerationRequest } from '../services/orderService';
import { generateAIIdentities } from '../services/geminiService';
import JSZip from 'https://esm.sh/jszip';

interface StepOrderGenerationProps {
  products: Product[];
  settings: AppSettings;
  onCancel: () => void;
}

const StepOrderGeneration: React.FC<StepOrderGenerationProps> = ({ products, settings, onCancel }) => {
  const getDefaultParentId = () => {
    const now = new Date();
    const year = now.getFullYear();
    const month = (now.getMonth() + 1).toString().padStart(2, '0');
    return `${year}${month}000001`;
  };

  const [request, setRequest] = useState<OrderGenerationRequest>({
    type: 'sfs',
    count: 3,
    productsPerOrder: 2,
    countryCode: settings.deliveryCountries[0]?.code || 'FR',
    salesChannel: settings.orderSalesChannels[0] || '',
    parentOrderId: getDefaultParentId(),
    orderIdPrefix: 'SFS-',
    startIndex: 1
  });

  const [generatedData, setGeneratedData] = useState<{ parent: any, subOrders: any[] } | null>(null);
  const [copyStatus, setCopyStatus] = useState<string | null>(null);
  const [isZipping, setIsZipping] = useState(false);
  const [isGeneratingAI, setIsGeneratingAI] = useState(false);

  const handleStrategyChange = (t: 'sfs' | 'ckc' | 'ropis') => {
    setRequest(prev => ({ 
      ...prev, 
      type: t,
      orderIdPrefix: `${t.toUpperCase()}-`
    }));
  };

  const handleGenerate = async () => {
    if (products.length === 0) {
      alert("No products available to generate orders.");
      return;
    }

    setIsGeneratingAI(true);
    try {
      // Step 1: Use AI to get fresh names and addresses
      const aiIdentities = await generateAIIdentities(request.countryCode || 'FR', request.count);

      // Step 2: Generate the technical payloads
      const data = generateOrderPayloads(request, products, settings, aiIdentities);
      setGeneratedData(data);
    } catch (err) {
      console.error("Failed to generate with AI:", err);
      // Fallback: Generate without AI if something fails
      const data = generateOrderPayloads(request, products, settings);
      setGeneratedData(data);
    } finally {
      setIsGeneratingAI(false);
    }
  };

  const handleCopy = (content: any, label: string) => {
    navigator.clipboard.writeText(JSON.stringify(content, null, 4));
    setCopyStatus(label);
    setTimeout(() => setCopyStatus(null), 2000);
  };

  const handleDownloadZip = async () => {
    if (!generatedData) return;
    setIsZipping(true);
    try {
      const zip = new JSZip();
      zip.file("parent_order.json", JSON.stringify(generatedData.parent, null, 4));
      const ordersFolder = zip.folder("orders");
      generatedData.subOrders.forEach((order) => {
        const orderId = order.order.id;
        ordersFolder?.file(`${orderId}.json`, JSON.stringify(order, null, 4));
      });

      const content = await zip.generateAsync({ type: "blob" });
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", URL.createObjectURL(content));
      downloadAnchorNode.setAttribute("download", `onestock_orders_package_${Date.now()}.zip`);
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
    } catch (err) {
      console.error(err);
      alert("Failed to generate ZIP archive.");
    } finally {
      setIsZipping(false);
    }
  };

  return (
