export interface OrderGenerationRequest {
  type: 'sfs' | 'ckc' | 'ropis';
  count: number;
  productsPerOrder: number;
  countryCode?: string;
  salesChannel?: string;
  parentOrderId: string;
  orderIdPrefix: string;
  startIndex: number;
}

// Updated FALLBACK_COUNTRY_DATA to use zip_code instead of zip to match CustomerIdentity structure
const FALLBACK_COUNTRY_DATA: Record<string, { firstNames: string[], lastNames: string[], addresses: { city: string, zip_code: string, lines: string[] }[] }> = {
  FR: {
    firstNames: ["Jean", "Marie", "William", "Elena", "Lucas", "Sophie", "Inès", "Pablo", "Oliver", "Amelia", "Théo", "Léa", "Manon", "Gabriel"],
    lastNames: ["Dupont", "Lefebvre", "Martin", "Bernard", "Dubois", "Thomas", "Robert", "Richard", "Petit", "Durand"],
    addresses: [{ city: "Toulouse", zip_code: "31400", lines: ["8 Rue des Trente-Six Ponts"] }]
  },
  GB: {
    firstNames: ["James", "Mary", "Robert"],
    lastNames: ["Smith", "Jones", "Taylor"],
    addresses: [{ city: "London", zip_code: "W1U 1EE", lines: ["10-12 James St"] }]
  },
  ES: {
    firstNames: ["Antonio", "Maria", "Jose"],
    lastNames: ["Garcia", "Rodriguez", "Gonzalez"],
    addresses: [{ city: "Madrid", zip_code: "28001", lines: ["Calle de Serrano, 1"] }]
  }
};

const getRandom = <T>(arr: T[]): T => arr[Math.floor(Math.random() * arr.length)];

export const generateOrderPayloads = (
  request: OrderGenerationRequest,
  availableProducts: Product[],
  settings: AppSettings,
  aiIdentities?: CustomerIdentity[]
) => {
  const { siteId, token } = settings;
  const now = Math.floor(Date.now() / 1000);
  const oneDay = 86400;
  const parentIdValue = request.parentOrderId;

  const countryCode = request.countryCode || 'FR';
  const fallbackLocalData = FALLBACK_COUNTRY_DATA[countryCode] || FALLBACK_COUNTRY_DATA.FR;

  const orders: any[] = [];
  let totalParentPrice = 0;
  const currency = availableProducts[0]?.currency || "EUR";

  for (let i = 0; i < request.count; i++) {
    const aiId = aiIdentities && aiIdentities[i];

    const firstName = aiId ? aiId.firstName : getRandom(fallbackLocalData.firstNames);
    const lastName = aiId ? aiId.lastName : getRandom(fallbackLocalData.lastNames);
    const title = aiId ? aiId.title : getRandom(['M.', 'Mme', '']);
    const email = `${firstName.toLowerCase()}.${lastName.toLowerCase().replace(' ', '')}@onestock-retail.com`;
    const phone = aiId ? aiId.phone : (countryCode === 'GB' ? '+44 7123456789' : '+33 612345678');

    const addressData = aiId ? aiId.address : getRandom(fallbackLocalData.addresses);
    const salesChannel = request.salesChannel || getRandom(settings.orderSalesChannels);

    let subtotal = 0;
    const shuffled = [...availableProducts].sort(() => 0.5 - Math.random());
    const selected = shuffled.slice(0, Math.min(request.productsPerOrder, availableProducts.length));

    const orderItems = selected.map(p => {
      const price = parseFloat(p.price) || 0;
      subtotal += price;
      return {
        item_id: p.sku,
        quantity: 1,
        pricing_details: {
          currency: p.currency || currency,
          original_price: price,
          price: price,
          original_unit_price: price,
          unit_price: price
        },
        information: {
          virtual: false,
          lot: `Lot : ${Math.floor(Math.random() * 10000000000)}`
        }
      };
    });

    const shippingPrice = request.type === 'sfs' ? 10 : 0;
    const totalPrice = parseFloat((subtotal + shippingPrice).toFixed(2));
    totalParentPrice += totalPrice;

    const currentIndex = request.startIndex + i;
    const counter = currentIndex.toString().padStart(8, '0');
    const orderId = `${request.orderIdPrefix}${counter}`;

    let orderTypes: string[] = [];
    if (request.type === 'sfs') orderTypes = ['ffs'];
    else if (request.type === 'ckc') orderTypes = ['ffs', 'ckc'];
    else orderTypes = ['ropis'];

    const orderPayload = {
      site_id: siteId,
      token: token,
      parent_order_id: parentIdValue,
      order: {
        id: orderId,
        types: orderTypes,
        sales_channel: salesChannel,
        reservation_rank: "01",
        on_available_stock: { auto_orchestrable: true },
        date: now,
        information: {
          amount_to_capture: `${totalPrice} ${currency}`,
          captured_amount: `${totalPrice} ${currency}`,
          amount_to_be_refunded: `0 ${currency}`,
          amount_refunded: `0 ${currency}`
        },
        delivery: {
          destination: {
            address: {
              city: addressData.city,
              // Fixed: addressData now consistently has zip_code
              zip_code: addressData.zip_code,
              lines: addressData.lines,
              regions: { country: { code: countryCode } },
              contact: {
                title,
                first_name: firstName,
                last_name: lastName,
                email,
                phone_number: phone
              }
            },
            ...(request.type !== 'sfs' ? { endpoint_id: getRandom(settings.stockEndpoints) } : {})
          },
          carrier: { name: "mock" }
        },
        delivery_promise: {
          original_delivery_option: {
            carbon_footprint: 100,
            cost: shippingPrice,
            cutoff: now + oneDay,
            delivery_method: request.type === 'sfs' ? "standard" : "collect",
            destination: {
              location: {
                country: countryCode,
                // Fixed: addressData now consistently has zip_code
                zip_code: addressData.zip_code
              }
            },
            eta_start: now + oneDay,
            eta_end: now + (oneDay * 2),
            shipment_number: 1,
            status: "valid"
          },
          sent_delivery_option: {
            eta_start: now + oneDay,
            eta_end: now + (oneDay * 2)
          }
        },
        customer: {
          email,
          first_name: firstName,
          last_name: lastName,
          phone_number: phone,
          title
        },
        pricing_details: {
          currency,
          original_price: totalPrice,
          price: totalPrice,
          price_including_tax: totalPrice,
          price_excluding_tax: parseFloat((totalPrice * 0.8).toFixed(2)),
          taxes: [
            {
              amount: parseFloat((totalPrice * 0.2).toFixed(2)),
              included_in_price: true
            }
          ],
          address: {
            city: addressData.city,
            // Fixed: addressData now consistently has zip_code
            zip_code: addressData.zip_code,
            lines: addressData.lines,
            regions: { country: { code: countryCode } },
            contact: {
              title: "",
              first_name: firstName,
              last_name: lastName,
              email,
              phone_number: phone
            }
          }
        },
        order_items: orderItems,
        shipping_fees: [
          {
            currency,
            original_price: shippingPrice,
            price: shippingPrice
          }
        ]
      }
    };

    orders.push(orderPayload);
  }

  const parentOrderPayload = {
    site_id: siteId,
    token: token,
    parent_order: {
      id: parentIdValue,
      pricing_details: {
        price: parseFloat(totalParentPrice.toFixed(2)),
        currency
      }
    }
  };

  return {
    parent: parentOrderPayload,
    subOrders: orders
  };
};

import { GoogleGenAI, Type } from "@google/genai";
import { Product } from "../types";

export interface CustomerIdentity {
  firstName: string;
  lastName: string;
  title: string;
  address: {
    city: string;
    zip_code: string;
    lines: string[];
  };
  phone: string;
}

export const generateAIIdentities = async (countryCode: string, count: number): Promise<CustomerIdentity[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Generate ${count} highly realistic and diverse delivery identities for the country: ${countryCode}. 
  CONTEXT: One customer is placing ${count} different orders to different locations.

  REQUIREMENTS:
  - Return ${count} unique delivery addresses (real cities, existing zip code formats, realistic street names for ${countryCode}).
  - For the first entry, provide a complete profile (First Name, Last Name, Title, Phone).
  - For the subsequent entries, you can vary the address significantly but keep the name and phone fields if possible, or provide varied ones (the application logic will prioritize the first one for the customer profile).

  Return as a JSON object with an "identities" array.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            identities: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  firstName: { type: Type.STRING },
                  lastName: { type: Type.STRING },
                  title: { type: Type.STRING },
                  address: {
                    type: Type.OBJECT,
                    properties: {
                      city: { type: Type.STRING },
                      zip_code: { type: Type.STRING },
                      lines: { type: Type.ARRAY, items: { type: Type.STRING } }
                    },
                    required: ["city", "zip_code", "lines"]
                  },
                  phone: { type: Type.STRING }
                },
                required: ["firstName", "lastName", "address", "phone"]
              }
            }
          }
        }
      }
    });

    const data = JSON.parse(response.text.trim());
    return data.identities || [];
  } catch (error) {
    console.error("Identity generation error:", error);
    return [];
  }
};

export const scanWebsiteForProducts = async (url: string, limit: number): Promise<Product[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const productTarget = Math.max(1, Math.ceil(limit / 3));

  const prompt = `Analyze the following URL to extract detailed product data: ${url}. 
  MISSION: Extract at least ${productTarget} different products from the page to help reach a total target of ${limit} unique SKUs (variants).
  Identify Mother ID (product_id) and all variant information (sizes).

  RETURN A STRICT JSON structure:
  { 
    "products": [ 
      { 
        "base_sku": "...", 
        "name": "...", 
        "description": "...", 
        "price": "...", 
        "compare_price": "...",
        "currency": "...",
        "color": "...", 
        "category": "...",
        "department": "...",
        "subdepartment": "...",
        "sizes": ["...", "..."], 
        "images": ["...", "..."]
      } 
    ] 
  }`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            products: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  base_sku: { type: Type.STRING },
                  name: { type: Type.STRING },
                  description: { type: Type.STRING },
                  price: { type: Type.STRING },
                  compare_price: { type: Type.STRING },
                  currency: { type: Type.STRING },
                  color: { type: Type.STRING },
                  category: { type: Type.STRING },
                  department: { type: Type.STRING },
                  subdepartment: { type: Type.STRING },
                  sizes: { type: Type.ARRAY, items: { type: Type.STRING } },
                  images: { type: Type.ARRAY, items: { type: Type.STRING } }
                },
                required: ["base_sku", "name", "price", "sizes", "images"]
              }
            }
          }
        }
      }
    });

    const data = JSON.parse(response.text.trim());
    const rawProducts = data.products || [];
    const flattenedProducts: Product[] = [];

    for (const p of rawProducts) {
      if (flattenedProducts.length >= limit) break;
      const allSizes = p.sizes && p.sizes.length > 0 ? p.sizes : ["Unique"];
      const motherId = p.base_sku || `ID-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;

      for (let index = 0; index < allSizes.length; index++) {
        if (flattenedProducts.length >= limit) break;
        const size = allSizes[index];
        const sizeSlug = size.replace(/[^a-zA-Z0-9]/g, '');
        const uniqueSku = `${motherId}-${sizeSlug || index}`;
        const mainImg = p.images?.[0] || '';

        flattenedProducts.push({
          id: uniqueSku, 
          sku: uniqueSku,
          parentSku: motherId,
          name: p.name,
          description: p.description || "No description",
          imageUrl: mainImg,
          productUrl: url,
          price: p.price.toString(),
          comparePrice: (p.compare_price || "0").toString(),
          currency: p.currency || "EUR",
          color: p.color || "N/A",
          size: size,
          category: p.category || "uncategorized",
          department: p.department || "Skincare",
          subdepartment: p.subdepartment || "Cleanser",
          weight: 0.4,
          length: 20,
          width: 15,
          height: 3,
          images_big: p.images || []
        });
      }
    }
    return flattenedProducts.slice(0, limit);
  } catch (error) {
    console.error("Extraction error:", error);
    return [];
  }
};

import { Product, AppSettings } from '../types';
import { CustomerIdentity } from './geminiService';

export interface OrderGenerationRequest {
  type: 'sfs' | 'ckc' | 'ropis';
  count: number;
  productsPerOrder: number;
  countryCode?: string;
  salesChannel?: string;
  parentOrderId: string;
  orderIdPrefix: string;
  startIndex: number;
}

const FALLBACK_COUNTRY_DATA: Record<string, { firstNames: string[], lastNames: string[], addresses: { city: string, zip_code: string, lines: string[] }[] }> = {
  FR: {
    firstNames: ["Jean", "Marie", "William", "Elena", "Lucas", "Sophie", "Inès", "Pablo", "Oliver", "Amelia", "Théo", "Léa", "Manon", "Gabriel"],
    lastNames: ["Dupont", "Lefebvre", "Martin", "Bernard", "Dubois", "Thomas", "Robert", "Richard", "Petit", "Durand"],
    addresses: [{ city: "Toulouse", zip_code: "31400", lines: ["8 Rue des Trente-Six Ponts"] }]
  },
  GB: {
    firstNames: ["James", "Mary", "Robert"],
    lastNames: ["Smith", "Jones", "Taylor"],
    addresses: [{ city: "London", zip_code: "W1U 1EE", lines: ["10-12 James St"] }]
  },
  ES: {
    firstNames: ["Antonio", "Maria", "Jose"],
    lastNames: ["Garcia", "Rodriguez", "Gonzalez"],
    addresses: [{ city: "Madrid", zip_code: "28001", lines: ["Calle de Serrano, 1"] }]
  }
};

const getRandom = <T>(arr: T[]): T => arr[Math.floor(Math.random() * arr.length)];

export const generateOrderPayloads = (
  request: OrderGenerationRequest,
  availableProducts: Product[],
  settings: AppSettings,
  aiIdentities?: CustomerIdentity[]
) => {
  const { siteId, token } = settings;
  const now = Math.floor(Date.now() / 1000);
  const oneDay = 86400;
  const parentIdValue = request.parentOrderId;

  const countryCode = request.countryCode || 'FR';
  const fallbackLocalData = FALLBACK_COUNTRY_DATA[countryCode] || FALLBACK_COUNTRY_DATA.FR;

  // Requirement: One Customer, Multiple Addresses
  // We use the first identity as the "Main Customer" for the whole batch
  const mainAiIdentity = aiIdentities && aiIdentities.length > 0 ? aiIdentities[0] : null;
  const mainFirstName = mainAiIdentity ? mainAiIdentity.firstName : getRandom(fallbackLocalData.firstNames);
  const mainLastName = mainAiIdentity ? mainAiIdentity.lastName : getRandom(fallbackLocalData.lastNames);
  const mainTitle = mainAiIdentity ? mainAiIdentity.title : getRandom(['M.', 'Mme', '']);
  const mainEmail = `${mainFirstName.toLowerCase()}.${mainLastName.toLowerCase().replace(' ', '')}@onestock-retail.com`;
  const mainPhone = mainAiIdentity ? mainAiIdentity.phone : (countryCode === 'GB' ? '+44 7123456789' : '+33 612345678');

  const orders: any[] = [];
  let totalParentPrice = 0;
  const currency = availableProducts[0]?.currency || "EUR";

  for (let i = 0; i < request.count; i++) {
    // Current AI profile for this specific sub-order's address
    const currentAiId = aiIdentities && aiIdentities[i] ? aiIdentities[i] : null;

    // Delivery address is unique per sub-order
    const addressData = currentAiId ? currentAiId.address : getRandom(fallbackLocalData.addresses);
    const salesChannel = request.salesChannel || getRandom(settings.orderSalesChannels);

    let subtotal = 0;
    const shuffled = [...availableProducts].sort(() => 0.5 - Math.random());
    const selected = shuffled.slice(0, Math.min(request.productsPerOrder, availableProducts.length));

    const orderItems = selected.map(p => {
      const price = parseFloat(p.price) || 0;
      subtotal += price;
      return {
        item_id: p.sku,
        quantity: 1,
        pricing_details: {
          currency: p.currency || currency,
          original_price: price,
          price: price,
          original_unit_price: price,
          unit_price: price
        },
        information: {
          virtual: false,
          lot: `Lot : ${Math.floor(Math.random() * 10000000000)}`
        }
      };
    });

    const shippingPrice = request.type === 'sfs' ? 10 : 0;
    const totalPrice = parseFloat((subtotal + shippingPrice).toFixed(2));
    totalParentPrice += totalPrice;

    const currentIndex = request.startIndex + i;
    const counter = currentIndex.toString().padStart(8, '0');
    const orderId = `${request.orderIdPrefix}${counter}`;

    let orderTypes: string[] = [];
    if (request.type === 'sfs') orderTypes = ['ffs'];
    else if (request.type === 'ckc') orderTypes = ['ffs', 'ckc'];
    else orderTypes = ['ropis'];

    const orderPayload = {
      site_id: siteId,
      token: token,
      parent_order_id: parentIdValue,
      order: {
        id: orderId,
        types: orderTypes,
        sales_channel: salesChannel,
        reservation_rank: "01",
        on_available_stock: { auto_orchestrable: true },
        date: now,
        information: {
          amount_to_capture: `${totalPrice} ${currency}`,
          captured_amount: `${totalPrice} ${currency}`,
          amount_to_be_refunded: `0 ${currency}`,
          amount_refunded: `0 ${currency}`
        },
        delivery: {
          destination: {
            address: {
              city: addressData.city,
              zip_code: addressData.zip_code,
              lines: addressData.lines,
              regions: { country: { code: countryCode } },
              contact: {
                // The contact name for delivery matches the customer name
                title: mainTitle,
                first_name: mainFirstName,
                last_name: mainLastName,
                email: mainEmail,
                phone_number: mainPhone
              }
            },
            ...(request.type !== 'sfs' ? { endpoint_id: getRandom(settings.stockEndpoints) } : {})
          },
          carrier: { name: "mock" }
        },
        delivery_promise: {
          original_delivery_option: {
            carbon_footprint: 100,
            cost: shippingPrice,
            cutoff: now + oneDay,
            delivery_method: request.type === 'sfs' ? "standard" : "collect",
            destination: {
              location: {
                country: countryCode,
                zip_code: addressData.zip_code
              }
            },
            eta_start: now + oneDay,
            eta_end: now + (oneDay * 2),
            shipment_number: 1,
            status: "valid"
          },
          sent_delivery_option: {
            eta_start: now + oneDay,
            eta_end: now + (oneDay * 2)
          }
        },
        customer: {
          // Fixed customer profile for the whole batch
          email: mainEmail,
          first_name: mainFirstName,
          last_name: mainLastName,
          phone_number: mainPhone,
          title: mainTitle
        },
        pricing_details: {
          currency,
          original_price: totalPrice,
          price: totalPrice,
          price_including_tax: totalPrice,
          price_excluding_tax: parseFloat((totalPrice * 0.8).toFixed(2)),
          taxes: [
            {
              amount: parseFloat((totalPrice * 0.2).toFixed(2)),
              included_in_price: true
            }
          ],
          address: {
            // Address here matches delivery address
            city: addressData.city,
            zip_code: addressData.zip_code,
            lines: addressData.lines,
            regions: { country: { code: countryCode } },
            contact: {
              title: mainTitle,
              first_name: mainFirstName,
              last_name: mainLastName,
              email: mainEmail,
              phone_number: mainPhone
            }
          }
        },
        order_items: orderItems,
        shipping_fees: [
          {
            currency,
            original_price: shippingPrice,
            price: shippingPrice
          }
        ]
      }
    };

    orders.push(orderPayload);
  }

  const parentOrderPayload = {
    site_id: siteId,
    token: token,
    parent_order: {
      id: parentIdValue,
      pricing_details: {
        price: parseFloat(totalParentPrice.toFixed(2)),
        currency
      }
    }
  };

  return {
    parent: parentOrderPayload,
    subOrders: orders
  };
};

import React, { useState } from 'react';
import { Product, AppSettings } from '../types';
import { generateOrderPayloads, OrderGenerationRequest } from '../services/orderService';
import { generateAIIdentities } from '../services/geminiService';
import JSZip from 'https://esm.sh/jszip';

interface StepOrderGenerationProps {
  products: Product[];
  settings: AppSettings;
  onCancel: () => void;
}

const StepOrderGeneration: React.FC<StepOrderGenerationProps> = ({ products, settings, onCancel }) => {
  const getDefaultParentId = () => {
    const now = new Date();
    const year = now.getFullYear();
    const month = (now.getMonth() + 1).toString().padStart(2, '0');
    return `${year}${month}000001`;
  };

  const [request, setRequest] = useState<OrderGenerationRequest>({
    type: 'sfs',
    count: 3,
    productsPerOrder: 2,
    countryCode: settings.deliveryCountries[0]?.code || 'FR',
    salesChannel: settings.orderSalesChannels[0] || '',
    parentOrderId: getDefaultParentId(),
    orderIdPrefix: 'SFS-',
    startIndex: 1
  });

  const [generatedData, setGeneratedData] = useState<{ parent: any, subOrders: any[] } | null>(null);
  const [copyStatus, setCopyStatus] = useState<string | null>(null);
  const [isZipping, setIsZipping] = useState(false);
  const [isGeneratingAI, setIsGeneratingAI] = useState(false);

  const handleStrategyChange = (t: 'sfs' | 'ckc' | 'ropis') => {
    setRequest(prev => ({ 
      ...prev, 
      type: t,
      orderIdPrefix: `${t.toUpperCase()}-`
    }));
  };

  /**
   * Helper to increment the Parent Order ID (YYYYMMXXXXXX)
   */
  const incrementParentId = (current: string): string => {
    if (current.length < 7) return current;
    const prefix = current.substring(0, 6); // YYYYMM
    const suffix = current.substring(6);    // XXXXXX
    const incrementedSuffix = (parseInt(suffix) + 1).toString().padStart(suffix.length, '0');
    return `${prefix}${incrementedSuffix}`;
  };

  const handleGenerate = async () => {
    if (products.length === 0) {
      alert("No products available to generate orders.");
      return;
    }

    setIsGeneratingAI(true);
    try {
      // Step 1: Use AI to get fresh names and addresses
      const aiIdentities = await generateAIIdentities(request.countryCode || 'FR', request.count);

      // Step 2: Generate the technical payloads
      const data = generateOrderPayloads(request, products, settings, aiIdentities);
      setGeneratedData(data);

      // Step 3: Auto-increment counters for the NEXT batch
      setRequest(prev => ({
        ...prev,
        startIndex: prev.startIndex + prev.count,
        parentOrderId: incrementParentId(prev.parentOrderId)
      }));

    } catch (err) {
      console.error("Failed to generate with AI:", err);
      // Fallback: Generate without AI if something fails
      const data = generateOrderPayloads(request, products, settings);
      setGeneratedData(data);

      // Still increment fallback
      setRequest(prev => ({
        ...prev,
        startIndex: prev.startIndex + prev.count,
        parentOrderId: incrementParentId(prev.parentOrderId)
      }));
    } finally {
      setIsGeneratingAI(false);
    }
  };

  const handleCopy = (content: any, label: string) => {
    navigator.clipboard.writeText(JSON.stringify(content, null, 4));
    setCopyStatus(label);
    setTimeout(() => setCopyStatus(null), 2000);
  };

  const handleDownloadZip = async () => {
    if (!generatedData) return;
    setIsZipping(true);
    try {
      const zip = new JSZip();
      zip.file("parent_order.json", JSON.stringify(generatedData.parent, null, 4));
      const ordersFolder = zip.folder("orders");
      generatedData.subOrders.forEach((order) => {
        const orderId = order.order.id;
        ordersFolder?.file(`${orderId}.json`, JSON.stringify(order, null, 4));
      });

      const content = await zip.generateAsync({ type: "blob" });
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", URL.createObjectURL(content));
      downloadAnchorNode.setAttribute("download", `onestock_orders_package_${Date.now()}.zip`);
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
    } catch (err) {
      console.error(err);
      alert("Failed to generate ZIP archive.");
    } finally {
      setIsZipping(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500 pb-20">
      <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-8">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-8">
          <div>
            <h2 className="text-2xl font-bold text-[#002D72] flex items-center gap-3">
              Customer Order Generation
              <span className="text-[10px] font-bold text-green-600 bg-green-50 px-2 py-0.5 rounded-full uppercase tracking-widest border border-green-100 flex items-center gap-1.5">
                <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                AI-Augmented
              </span>
            </h2>
            <p className="text-sm text-gray-500 mt-1">Simulate real customer traffic using AI-generated identities and technical payloads.</p>
          </div>
          <div className="flex gap-3">
            <button onClick={onCancel} className="px-4 py-2 text-sm font-semibold text-gray-600 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors">Cancel</button>
            <button 
              onClick={handleGenerate}
              disabled={isGeneratingAI}
              className="px-6 py-2 bg-[#002D72] text-white font-bold rounded-lg hover:bg-[#001F4D] shadow-lg flex items-center gap-2 transition-all text-sm disabled:opacity-70 disabled:cursor-wait"
            >
              {isGeneratingAI ? (
                <>
                  <svg className="w-4 h-4 animate-spin" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                  AI Generating Batch...
                </>
              ) : (
                <>
                  Generate Batch & Auto-Increment
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.5 14.25v-2.625a3.375 3.375 0 00-3.375-3.375h-1.5A1.125 1.125 0 0113.5 7.125v-1.5a3.375 3.375 0 00-3.375-3.375H8.25m3.75 9v6m3-3H9m1.5-12H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 00-9-9z" /></svg>
                </>
              )}
            </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 p-6 bg-gray-50 rounded-xl border border-gray-100">
          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Order Strategy</label>
            <div className="grid grid-cols-3 gap-2">
              {(['sfs', 'ckc', 'ropis'] as const).map(t => (
                <button 
                  key={t}
                  onClick={() => handleStrategyChange(t)}
                  className={`py-2 text-[10px] font-bold rounded-lg uppercase tracking-wider transition-all border ${
                    request.type === t ? 'bg-[#002D72] border-[#002D72] text-white' : 'bg-white border-gray-200 text-gray-400 hover:border-blue-200'
                  }`}
                >
                  {t}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Destination Country (AI Target)</label>
            <select 
              value={request.countryCode}
              onChange={e => setRequest(prev => ({ ...prev, countryCode: e.target.value }))}
              className="w-full px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-bold text-onestock-blue outline-none focus:border-onestock-blue"
