export const generateAIIdentities = async (countryCode: string, count: number): Promise<CustomerIdentity[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Generate ${count} highly realistic and diverse delivery identities for the country: ${countryCode}. 
  CONTEXT: One customer is placing ${count} different orders to different locations.

  REQUIREMENTS:
  - Return ${count} unique delivery addresses (real cities, existing zip code formats, realistic street names for ${countryCode}).
  - For the first entry, provide a complete profile (First Name, Last Name, Title, Phone).
  - For the subsequent entries, you can vary the address significantly but keep the name and phone fields if possible, or provide varied ones (the application logic will prioritize the first one for the customer profile).

  Return as a JSON object with an "identities" array.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            identities: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  firstName: { type: Type.STRING },
                  lastName: { type: Type.STRING },
                  title: { type: Type.STRING },
                  address: {
                    type: Type.OBJECT,
                    properties: {
                      city: { type: Type.STRING },
                      zip_code: { type: Type.STRING },
                      lines: { type: Type.ARRAY, items: { type: Type.STRING } }
                    },
                    required: ["city", "zip_code", "lines"]
                  },
                  phone: { type: Type.STRING }
                },
                required: ["firstName", "lastName", "address", "phone"]
              }
            }
          }
        }
      }
    });

    const data = JSON.parse(response.text.trim());
    return data.identities || [];
  } catch (error) {
    console.error("Identity generation error:", error);
    return [];
  }
};

export const scanWebsiteForProducts = async (url: string, limit: number): Promise<ScanResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const productTarget = Math.max(1, Math.ceil(limit / 3));

  // Prompt optimisé pour ne pas dépendre du schéma JSON si googleSearch est utilisé
  const prompt = `Analyze the following website and extract products: ${url}. 
  MISSION: Extract at least ${productTarget} different products from the page to help reach a total target of ${limit} unique SKUs (variants).
  Identify Mother ID (product_id) and all variant information (sizes).

  IMPORTANT: Provide your response strictly as a JSON block inside markdown code tags.
  JSON structure example:
  { 
    "products": [ 
      { 
        "base_sku": "...", 
        "name": "...", 
        "description": "...", 
        "price": "...", 
        "currency": "...",
        "color": "...", 
        "sizes": ["S", "M"], 
        "images": ["url1"]
      } 
    ] 
  }`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });

    const text = response.text || "";

    // Extraction manuelle du JSON au cas où le modèle ajoute du texte avant/après à cause de l'outil de recherche
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (!jsonMatch) {
      throw new Error("Impossible de trouver le bloc JSON dans la réponse.");
    }

    const data = JSON.parse(jsonMatch[0]);
    const rawProducts = data.products || [];

    // Extraction des sources de grounding (obligatoire pour Google Search)
    const sources: GroundingSource[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          sources.push({
            title: chunk.web.title || "Source",
            uri: chunk.web.uri
          });
        }
      });
    }

    const flattenedProducts: Product[] = [];
    for (const p of rawProducts) {
      if (flattenedProducts.length >= limit) break;
      const allSizes = p.sizes && p.sizes.length > 0 ? p.sizes : ["Unique"];
      const motherId = p.base_sku || `ID-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;

      for (let index = 0; index < allSizes.length; index++) {
        if (flattenedProducts.length >= limit) break;
        const size = allSizes[index];
        const sizeSlug = size.replace(/[^a-zA-Z0-9]/g, '');
        const uniqueSku = `${motherId}-${sizeSlug || index}`;
        const mainImg = p.images?.[0] || '';

        flattenedProducts.push({
          id: uniqueSku, 
          sku: uniqueSku,
          parentSku: motherId,
          name: p.name,
          description: p.description || "No description",
          imageUrl: mainImg,
          productUrl: url,
          price: p.price.toString(),
          comparePrice: (p.compare_price || "0").toString(),
          currency: p.currency || "EUR",
          color: p.color || "N/A",
          size: size,
          category: p.category || "uncategorized",
          department: p.department || "General",
          subdepartment: p.subdepartment || "General",
          weight: 0.4,
          length: 20,
          width: 15,
          height: 3,
          images_big: p.images || []
        });
      }
    }

    return {
      products: flattenedProducts.slice(0, limit),
      sources
    };
  } catch (error: any) {
    console.error("Extraction error:", error);
    throw error;
  }
};

import React, { useEffect, useState } from 'react';
import { Product, GroundingSource } from '../types';
import { scanWebsiteForProducts } from '../services/geminiService';
import { fetchImageAsBase64 } from '../utils/imageUtils';

interface StepScanningProps {
  url: string;
  limit: number;
  onComplete: (products: Product[], sources: GroundingSource[]) => void;
  onError: (msg: string) => void;
}

const StepScanning: React.FC<StepScanningProps> = ({ url, limit, onComplete, onError }) => {
  const [progress, setProgress] = useState(0);
  const [status, setStatus] = useState('Starting Visual Crawler...');
  const [mirrorProgress, setMirrorProgress] = useState({ current: 0, total: 0 });

  useEffect(() => {
    let isMounted = true;

    const runScan = async () => {
      try {
        setStatus(`Analyzing catalog (${limit} target items)...`);
        setProgress(5);

        const scanResult = await scanWebsiteForProducts(url, limit);
        const results = scanResult.products;
        const sources = scanResult.sources;

        if (!isMounted) return;

        if (results.length === 0) {
          onError("AI could not identify valid products. Please check the URL.");
          return;
        }

        setProgress(25);
        setStatus(`${results.length} products detected. Capturing visuals...`);

        setMirrorProgress({ current: 0, total: results.length });

        const mirroredProducts = [];
        for (let i = 0; i < results.length; i++) {
          const product = results[i];
          setStatus(`Processing: [${i + 1}/${results.length}] ${product.name.substring(0, 20)}...`);

          try {
            const base64Image = await fetchImageAsBase64(product.imageUrl);
            mirroredProducts.push({
              ...product,
              imageUrl: base64Image
            });
          } catch (e) {
            console.warn(`Mirroring failed for ${product.sku}, using direct link fallback.`);
            mirroredProducts.push(product);
          }

          setMirrorProgress({ current: i + 1, total: results.length });
          setProgress(25 + Math.floor(((i + 1) / results.length) * 75));
        }

        if (!isMounted) return;

        setStatus('OneStock synchronization complete.');
        setProgress(100);
        setTimeout(() => onComplete(mirroredProducts, sources), 500);
      } catch (err: any) {
        console.error("Scan error caught:", err);
        if (isMounted) onError(`Scan failed: ${err.message || 'Unknown API Error'}`);
      }
    };

    runScan();
    return () => { isMounted = false; };
  }, [url, limit, onComplete, onError]);

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-12 text-center h-full flex flex-col items-center justify-center">
      <div className="relative w-28 h-28 mb-8">
        <div className="absolute inset-0 border-4 border-gray-100 rounded-full"></div>
        <div className="absolute inset-0 border-4 border-[#002D72] rounded-full border-t-transparent animate-spin"></div>
        <div className="absolute inset-0 flex items-center justify-center text-xl font-bold text-[#002D72]">
          {progress}%
        </div>
      </div>

      <h2 className="text-2xl font-bold text-gray-900 mb-2 font-display">Smart Catalog Capture</h2>
      <p className="text-gray-500 mb-8 max-w-md mx-auto h-12 flex items-center justify-center text-sm leading-relaxed italic">
        {status}
      </p>

      <div className="w-full max-w-md space-y-3">
        <div className="bg-gray-100 rounded-full h-2.5 overflow-hidden">
          <div 
            className="bg-[#002D72] h-full transition-all duration-300"
            style={{ width: `${progress}%` }}
          ></div>
        </div>

        {mirrorProgress.total > 0 && (
          <div className="flex justify-between items-center text-[10px] font-bold text-gray-400 uppercase tracking-widest">
            <span>Asset Mirroring Status</span>
            <span className="text-onestock-blue">{mirrorProgress.current} / {mirrorProgress.total}</span>
          </div>
        )}
      </div>
    </div>
  );
};

