    setTargetUrl(url);
    setTargetLimit(limit);
    setIsViewingHistory(false);
    setError(null);
    setCurrentStep(AppStep.SCANNING);
  };

  const handleScanComplete = (results: Product[], sources: GroundingSource[]) => {
    setProducts(results);
    setGroundingSources(sources);
    setSelectedIds(new Set(results.map(p => p.id)));
    setCurrentStep(AppStep.RESULTS);
  };

  const handleUpdateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const handleStartImport = () => {
    setCurrentStep(AppStep.IMPORTING);
  };

  const handleImportComplete = () => {
    const newSite: ProcessedSite = {
      id: Date.now().toString(),
      url: targetUrl,
      hostname: new URL(targetUrl).hostname,
      date: new Date().toLocaleString(),
      products: products,
      sources: groundingSources
    };
    setHistory(prev => [newSite, ...prev]);
    setCurrentStep(AppStep.SUCCESS);
  };

  const handleGenerateJson = (selected: Product[]) => {
    setSelectedProductsForJson(selected);
    setCurrentStep(AppStep.JSON_VIEWER);
  };

  const handleImportJson = (site: ProcessedSite) => {
    if (site && site.id && site.products && Array.isArray(site.products)) {
      setHistory(prev => {
        if (prev.some(item => item.id === site.id)) return prev;
        return [site, ...prev];
      });
      alert('Result successfully imported to history.');
    } else {
      alert('Invalid JSON format.');
    }
  };

  const handleViewHistoryItem = (site: ProcessedSite) => {
    setTargetUrl(site.url);
    setProducts(site.products);
    setGroundingSources(site.sources || []);
    setSelectedIds(new Set(site.products.map(p => p.id)));
    setIsViewingHistory(true);
    setCurrentStep(AppStep.RESULTS);
  };

  const reset = () => {
    setTargetUrl('');
    setProducts([]);
    setGroundingSources([]);
    setSelectedIds(new Set());
    setIsViewingHistory(false);
    setCurrentStep(AppStep.INPUT);
    setError(null);
  };

  const goToInput = () => {
    setTargetUrl('');
    setProducts([]);
    setGroundingSources([]);
    setSelectedIds(new Set());
    setIsViewingHistory(false);
    setCurrentStep(AppStep.INPUT);
  };

  // Only pass items that are currently selected in Step 2 to sub-tools
  const selectedProducts = products.filter(p => selectedIds.has(p.id));

  return (
    <div className="flex h-screen overflow-hidden text-gray-800 bg-[#F8FAFC]">
      <Sidebar 
        currentStep={currentStep} 
        onReset={reset} 
        onGoToHistory={() => setCurrentStep(AppStep.HISTORY)}
        onNewImport={goToInput}
        onGoToSettings={() => setCurrentStep(AppStep.SETTINGS)}
        onGoToStock={() => setCurrentStep(AppStep.STOCK_UPDATE)}
        onGoToOrders={() => setCurrentStep(AppStep.ORDER_GENERATION)}
        hasProducts={selectedProducts.length > 0}
      />

      <div className="flex-1 flex flex-col min-w-0">
        <Header />

        <main className="flex-1 overflow-y-auto p-6 lg:p-10">
          <div className="max-w-6xl mx-auto h-full">
            {currentStep === AppStep.SETTINGS && (
              <Settings settings={settings} onSave={setSettings} />
            )}

            {currentStep === AppStep.STOCK_UPDATE && (
              <StepStockUpdate 
                products={selectedProducts} 
                settings={settings} 
                onCancel={() => setCurrentStep(AppStep.RESULTS)}
              />
            )}

            {currentStep === AppStep.ORDER_GENERATION && (
              <StepOrderGeneration 
                products={selectedProducts} 
                settings={settings} 
                onCancel={() => setCurrentStep(AppStep.RESULTS)}
              />
            )}

            {currentStep === AppStep.HISTORY && (
              <StepHistory 
                history={history} 
                onViewItem={handleViewHistoryItem} 
                onNewImport={goToInput}
                settings={settings}
                onImportJson={handleImportJson}
              />
            )}

            {currentStep === AppStep.INPUT && (
              <StepInput onStart={handleStartScan} />
            )}

            {currentStep === AppStep.SCANNING && (
              <StepScanning 
                url={targetUrl} 
                limit={targetLimit}
                onComplete={handleScanComplete} 
                onError={(msg) => { setError(msg); setCurrentStep(AppStep.INPUT); }} 
              />
            )}

            {currentStep === AppStep.RESULTS && (
              <StepResults 
                products={products} 
                url={targetUrl} 
                settings={settings}
                sources={groundingSources}
                selectedIds={selectedIds}
                onSelectionChange={setSelectedIds}
                onImport={handleStartImport}
                onCancel={reset}
                onGenerateJson={handleGenerateJson}
                isHistoryView={isViewingHistory}
                onUpdateProduct={handleUpdateProduct}
              />
            )}

            {currentStep === AppStep.JSON_VIEWER && (
              <StepJsonViewer 
                selectedProducts={selectedProductsForJson}
                settings={settings}
                onBack={() => setCurrentStep(AppStep.RESULTS)}
              />
            )}

            {currentStep === AppStep.IMPORTING && (
              <StepImporting 
                products={selectedProducts} 
                url={targetUrl} 
                onComplete={handleImportComplete} 
              />
            )}

            {currentStep === AppStep.SUCCESS && (
              <StepSuccess onReset={() => setCurrentStep(AppStep.INPUT)} url={targetUrl} />
            )}

            {error && (
              <div className="mt-4 p-4 bg-red-50 border border-red-200 text-red-700 rounded-lg flex flex-col gap-1 animate-in slide-in-from-top-2">
                <div className="flex items-center gap-3">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                  <span className="text-sm font-bold">Extraction Error</span>
                </div>
                <p className="text-xs ml-8 opacity-80">{error}</p>
              </div>
            )}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useState } from 'react';
import { Product, GroundingSource } from '../types';
import { scanWebsiteForProducts } from '../services/geminiService';
import { fetchImageAsBase64 } from '../utils/imageUtils';

interface StepScanningProps {
  url: string;
  limit: number;
  onComplete: (products: Product[], sources: GroundingSource[]) => void;
  onError: (msg: string) => void;
}

const StepScanning: React.FC<StepScanningProps> = ({ url, limit, onComplete, onError }) => {
  const [progress, setProgress] = useState(0);
  const [status, setStatus] = useState('Starting Visual Crawler...');
  const [mirrorProgress, setMirrorProgress] = useState({ current: 0, total: 0 });

  useEffect(() => {
    let isMounted = true;

    const runScan = async () => {
      try {
        setStatus(`Analyzing catalog (${limit} target items)...`);
        setProgress(5);

        const scanResult = await scanWebsiteForProducts(url, limit);
        const results = scanResult.products;
        const sources = scanResult.sources;

        if (!isMounted) return;

        if (results.length === 0) {
          onError("AI could not identify valid products. Please check the URL.");
          return;
        }

        setProgress(25);
        setStatus(`${results.length} products detected. Capturing visuals...`);

        setMirrorProgress({ current: 0, total: results.length });

        const mirroredProducts = [];
        for (let i = 0; i < results.length; i++) {
          const product = results[i];
          setStatus(`Processing: [${i + 1}/${results.length}] ${product.name.substring(0, 20)}...`);

          try {
            const base64Image = await fetchImageAsBase64(product.imageUrl);
            mirroredProducts.push({
              ...product,
              imageUrl: base64Image
            });
          } catch (e) {
            console.warn(`Mirroring failed for ${product.sku}, using direct link fallback.`);
            mirroredProducts.push(product);
          }

          setMirrorProgress({ current: i + 1, total: results.length });
          setProgress(25 + Math.floor(((i + 1) / results.length) * 75));
        }

        if (!isMounted) return;

        setStatus('OneStock synchronization complete.');
        setProgress(100);
        setTimeout(() => onComplete(mirroredProducts, sources), 500);
      } catch (err: any) {
        console.error("Scan error catch:", err);
        if (isMounted) onError(`Scan failed: ${err.message || 'Unknown API Error'}`);
      }
    };

    runScan();
    return () => { isMounted = false; };
  }, [url, limit, onComplete, onError]);

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-12 text-center h-full flex flex-col items-center justify-center">
      <div className="relative w-28 h-28 mb-8">
        <div className="absolute inset-0 border-4 border-gray-100 rounded-full"></div>
        <div className="absolute inset-0 border-4 border-[#002D72] rounded-full border-t-transparent animate-spin"></div>
        <div className="absolute inset-0 flex items-center justify-center text-xl font-bold text-[#002D72]">
          {progress}%
        </div>
      </div>

      <h2 className="text-2xl font-bold text-gray-900 mb-2 font-display">Smart Catalog Capture</h2>
      <p className="text-gray-500 mb-8 max-w-md mx-auto h-12 flex items-center justify-center text-sm leading-relaxed italic">
        {status}
      </p>

      <div className="w-full max-w-md space-y-3">
        <div className="bg-gray-100 rounded-full h-2.5 overflow-hidden">
          <div 
            className="bg-[#002D72] h-full transition-all duration-300"
            style={{ width: `${progress}%` }}
          ></div>
        </div>

        {mirrorProgress.total > 0 && (
          <div className="flex justify-between items-center text-[10px] font-bold text-gray-400 uppercase tracking-widest">
            <span>Asset Mirroring Status</span>
            <span className="text-onestock-blue">{mirrorProgress.current} / {mirrorProgress.total}</span>
          </div>
        )}
      </div>
    </div>
  );
};

export default StepScanning;

import React, { useState, useMemo } from 'react';
import { Product, AppSettings, GroundingSource } from '../types';
import ImageModal from './ImageModal';

interface StepResultsProps {
  products: Product[];
  url: string;
  settings: AppSettings;
  sources?: GroundingSource[];
  selectedIds: Set<string>;
  onSelectionChange: (ids: Set<string>) => void;
  onImport: () => void;
  onCancel: () => void;
  onGenerateJson: (selectedProducts: Product[]) => void;
  onUpdateProduct: (product: Product) => void;
  isHistoryView?: boolean;
}

const StepResults: React.FC<StepResultsProps> = ({ 
  products, 
  url, 
  settings,
  sources = [],
  selectedIds,
  onSelectionChange,
  onImport, 
  onCancel, 
  onGenerateJson, 
  onUpdateProduct,
  isHistoryView = false 
}) => {
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [isMassEditOpen, setIsMassEditOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [massEditField, setMassEditField] = useState<keyof Product>('name');
  const [massEditValue, setMassEditValue] = useState('');

  const filteredProducts = useMemo(() => {
    if (!searchTerm.trim()) return products;
    const lowSearch = searchTerm.toLowerCase();
    return products.filter(p => 
      p.name.toLowerCase().includes(lowSearch) ||
      p.sku.toLowerCase().includes(lowSearch) ||
      p.parentSku.toLowerCase().includes(lowSearch) ||
      p.category.toLowerCase().includes(lowSearch) ||
      p.color.toLowerCase().includes(lowSearch) ||
      p.department.toLowerCase().includes(lowSearch) ||
      p.description.toLowerCase().includes(lowSearch)
    );
  }, [products, searchTerm]);

  const toggleSelectAll = () => {
    const allFilteredSelected = filteredProducts.every(p => selectedIds.has(p.id));
    const newSelected = new Set(selectedIds);

    if (allFilteredSelected) {
      filteredProducts.forEach(p => newSelected.delete(p.id));
    } else {
      filteredProducts.forEach(p => newSelected.add(p.id));
    }
    onSelectionChange(newSelected);
  };

  const toggleSelect = (id: string) => {
    const newSelected = new Set(selectedIds);
    if (newSelected.has(id)) {
      newSelected.delete(id);
    } else {
      newSelected.add(id);
    }
    onSelectionChange(newSelected);
  };

  const handleFieldChange = (product: Product, field: keyof Product, value: string | number) => {
    onUpdateProduct({ ...product, [field]: value });
  };

  const applyMassEdit = () => {
    if (selectedIds.size === 0) return;

    products.forEach(p => {
      if (selectedIds.has(p.id)) {
        let value: any = massEditValue;
        if (['weight', 'length', 'width', 'height'].includes(massEditField)) {
          value = parseFloat(massEditValue) || 0;
        }
        onUpdateProduct({ ...p, [massEditField]: value });
      }
    });

    setIsMassEditOpen(false);
    setMassEditValue('');
  };

  const handleDownloadJson = () => {
    const selected = products.filter(p => selectedIds.has(p.id));
    if (selected.length === 0) {
      alert("Please select at least one article.");
      return;
    }

    const items = selected.map(p => ({
      id: p.sku,
      category_ids: [p.category],
      is_default: true,
      product_id: p.parentSku,
      features: {
        en: {
          color: [p.color],
          departement: [p.department],
          subdepartement: [p.subdepartment],
          image: [p.imageUrl],
          images_big: [p.imageUrl],
          long_description: [p.description],
          name: [p.name],
          price: [p.price],
          size: [p.size],
          weight: [p.weight]
        },
        fr: {
          color: [p.color],
          departement: [p.department],
          subdepartement: [p.subdepartment],
          image: [p.imageUrl],
          images_big: [p.imageUrl],
          long_description: [p.description],
          name: [p.name],
          price: [p.price],
          size: [p.size],
          weight: [p.weight]
        }
      },
      sales_channels_features: {
        [settings.salesChannel]: {
          compare_at_price: parseFloat(p.comparePrice || "0"),
          currency: p.currency,
          price: parseFloat(p.price)
        }
      },
      length: p.length,
      width: p.width,
      height: p.height,
      weight: p.weight
    }));

    const jsonContent = JSON.stringify({ items }, null, 4);
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(jsonContent);
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", `onestock_export_${Date.now()}.json`);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const editableInputClass = "w-full bg-transparent border-none focus:ring-1 focus:ring-onestock-blue rounded px-1 py-0.5 text-inherit transition-all hover:bg-gray-50 focus:bg-white";

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-500 max-w-full relative pb-10">
      {selectedProduct && (
        <ImageModal 
          imageUrl={selectedProduct.imageUrl} 
          productName={selectedProduct.name} 
          onClose={() => setSelectedProduct(null)} 
        />
      )}

      {isMassEditOpen && (
        <div className="fixed inset-0 z-[110] flex justify-end animate-in fade-in duration-200">
          <div className="absolute inset-0 bg-black/20 backdrop-blur-sm" onClick={() => setIsMassEditOpen(false)}></div>
          <div className="relative w-96 bg-white shadow-2xl h-full p-8 animate-in slide-in-from-right duration-300 border-l border-gray-200">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-bold text-[#002D72]">Mass Edit Selection</h3>
              <button onClick={() => setIsMassEditOpen(false)} className="text-gray-400 hover:text-gray-600">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="space-y-6">
              <p className="text-sm text-gray-500">Apply a new value to all <strong>{selectedIds.size}</strong> selected items.</p>

              <div>
                <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Target Field</label>
                <select 
                  value={massEditField}
                  onChange={(e) => setMassEditField(e.target.value as keyof Product)}
                  className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl text-sm font-bold outline-none focus:border-onestock-blue"
                >
                  <option value="name">Product Name (name)</option>
                  <option value="parentSku">Mother ID (product_id)</option>
                  <option value="description">Description (long_description)</option>
                  <option value="imageUrl">Image URL (image)</option>
                  <option value="category">Category (category_ids)</option>
                  <option value="department">Department (departement)</option>
                  <option value="subdepartment">Sub-Department (subdepartement)</option>
                  <option value="color">Color (color)</option>
                  <option value="size">Size (size)</option>
                  <option value="price">Price (price)</option>
                  <option value="comparePrice">Compare Price (compare_at_price)</option>
                  <option value="weight">Weight (weight)</option>
                </select>
              </div>

              <div>
                <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">New Value</label>
                <input 
                  type="text"
                  value={massEditValue}
                  onChange={(e) => setMassEditValue(e.target.value)}
                  placeholder="Enter value..."
                  className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl text-sm outline-none focus:border-onestock-blue"
                />
              </div>

              <button 
                onClick={applyMassEdit}
                disabled={selectedIds.size === 0}
                className="w-full py-4 bg-[#002D72] text-white font-bold rounded-xl hover:bg-[#001F4D] transition-all shadow-lg flex items-center justify-center gap-2"
              >
                Apply to {selectedIds.size} items
              </button>
            </div>
          </div>
        </div>
      )}

      {sources.length > 0 && (
        <div className="bg-white px-6 py-4 rounded-xl border border-blue-100 shadow-sm animate-in fade-in slide-in-from-top-2">
          <div className="flex items-center gap-2 mb-3">
            <svg className="w-4 h-4 text-onestock-blue" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.899a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" /></svg>
            <h3 className="text-xs font-bold text-onestock-blue uppercase tracking-widest">Grounding Sources (Search Results)</h3>
          </div>
          <div className="flex flex-wrap gap-2">
            {sources.map((source, i) => (
              <a 
                key={i} 
                href={source.uri} 
                target="_blank" 
                rel="noopener noreferrer"
                className="inline-flex items-center px-2 py-1 bg-blue-50 text-onestock-blue text-[10px] font-medium rounded border border-blue-200 hover:bg-blue-100 transition-colors"
              >
                {source.title.length > 30 ? source.title.substring(0, 30) + '...' : source.title}
                <svg className="w-3 h-3 ml-1 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
              </a>
            ))}
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row gap-4 items-stretch md:items-center justify-between bg-white px-6 py-4 rounded-xl border border-gray-200 shadow-sm">
        <div className="flex-1 min-w-0">
          <h2 className="text-xl font-bold text-[#002D72]">Step 2: Hierarchy Verification</h2>
          <p className="text-sm text-gray-500">Edit cells directly. Only selected items ({selectedIds.size}) are used in subsequent tools.</p>
        </div>

        <div className="flex flex-wrap items-center gap-3">
          <div className="relative group min-w-[200px]">
            <svg className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
            <input 
              type="text"
              placeholder="Search items..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 text-sm bg-gray-50 border border-gray-200 rounded-lg focus:ring-1 focus:ring-onestock-blue focus:bg-white outline-none transition-all"
            />
          </div>

          <button 
            onClick={() => setIsMassEditOpen(true)}
            disabled={selectedIds.size === 0}
            className="px-3 py-2 text-xs font-bold text-gray-600 border border-gray-300 rounded-lg hover:bg-gray-50 transition-all flex items-center gap-2 disabled:opacity-30"
          >
            Mass Edit
          </button>

          <button 
            onClick={() => onGenerateJson(products.filter(p => selectedIds.has(p.id)))}
