import StockExportModal from './StockExportModal';

interface StepStockUpdateProps {
  products: Product[];
  settings: AppSettings;
  onCancel: () => void;
}

const StepStockUpdate: React.FC<StepStockUpdateProps> = ({ products, settings, onCancel }) => {
  const [viewMode, setViewMode] = useState<'table' | 'payload'>('table');
  const [searchTerm, setSearchTerm] = useState('');
  const [isExportingApi, setIsExportingApi] = useState(false);
  const [stockLevels, setStockLevels] = useState<Record<string, Record<string, number>>>(() => {
    const initial: Record<string, Record<string, number>> = {};
    products.forEach(p => {
      initial[p.sku] = {};
      settings.stockEndpoints.forEach(ep => {
        initial[p.sku][ep] = 0;
      });
    });
    return initial;
  });

  const [payloadContent, setPayloadContent] = useState('');
  const [copySuccess, setCopySuccess] = useState(false);

  const filteredProducts = useMemo(() => {
    if (!searchTerm.trim()) return products;
    const lowSearch = searchTerm.toLowerCase();
    return products.filter(p => 
      p.name.toLowerCase().includes(lowSearch) ||
      p.sku.toLowerCase().includes(lowSearch)
    );
  }, [products, searchTerm]);

  const handleStockChange = (sku: string, endpoint: string, val: string) => {
    const numVal = parseInt(val) || 0;
    setStockLevels(prev => ({
      ...prev,
      [sku]: {
        ...prev[sku],
        [endpoint]: numVal
      }
    }));
  };

  const applyToColumn = (endpoint: string) => {
    const valStr = prompt(`Enter stock quantity to apply to all visible rows for "${endpoint}":`, "0");
    if (valStr === null) return;
    const val = parseInt(valStr) || 0;

    setStockLevels(prev => {
      const updated = { ...prev };
      filteredProducts.forEach(p => {
        if (!updated[p.sku]) updated[p.sku] = {};
        updated[p.sku][endpoint] = val;
      });
      return updated;
    });
  };

  const fillRandom = () => {
    setStockLevels(prev => {
      const updated = { ...prev };
      products.forEach(p => {
        settings.stockEndpoints.forEach(ep => {
          const isZero = Math.random() < 0.5;
          updated[p.sku][ep] = isZero ? 0 : Math.floor(Math.random() * 25) + 1;
        });
      });
      return updated;
    });
  };

  const clearAll = () => {
    setStockLevels(prev => {
      const updated = { ...prev };
      products.forEach(p => {
        settings.stockEndpoints.forEach(ep => {
          updated[p.sku][ep] = 0;
        });
      });
      return updated;
    });
  };

  const getStockDataArray = () => {
    const formattedStocks: { item_id: string; endpoint_id: string; quantity: number }[] = [];
    Object.entries(stockLevels).forEach(([sku, endpoints]) => {
      Object.entries(endpoints).forEach(([ep, qty]) => {
        formattedStocks.push({
          item_id: sku,
          endpoint_id: ep,
          quantity: qty
        });
      });
    });
    return formattedStocks;
  };

  const generatePayload = () => {
    const formattedStocks = getStockDataArray();
    const payload = {
      token: settings.token,
      site_id: settings.siteId,
      import: {
        incremental: false
      },
      stocks: formattedStocks
    };

    const json = JSON.stringify(payload, null, 4);
    setPayloadContent(json);
    setViewMode('payload');
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(payloadContent);
    setCopySuccess(true);
    setTimeout(() => setCopySuccess(false), 2000);
  };

  const handleDownload = () => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(payloadContent);
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", `onestock_stock_payload_${Date.now()}.json`);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  if (viewMode === 'payload') {
    return (
      <div className="space-y-6 animate-in fade-in zoom-in-95 duration-500">
        <div className="flex items-center justify-between bg-white px-6 py-4 rounded-xl border border-gray-200 shadow-sm">
          <div>
            <h2 className="text-xl font-bold text-[#002D72]">Stock Payload Generation</h2>
            <p className="text-sm text-gray-500">Technical body for inventory synchronization across <strong>{settings.stockEndpoints.length}</strong> endpoints.</p>
          </div>
          <div className="flex gap-3">
            <button 
              onClick={() => setViewMode('table')}
              className="px-4 py-2 text-sm font-semibold text-gray-600 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
            >
              Back to Table
            </button>
            <button 
              onClick={handleCopy}
              className={`px-4 py-2 text-sm font-bold border rounded-lg transition-all flex items-center gap-2 ${
                copySuccess ? 'bg-green-50 border-green-200 text-green-600' : 'bg-white border-onestock-blue text-onestock-blue hover:bg-blue-50'
              }`}
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" /></svg>
              {copySuccess ? 'Copied!' : 'Copy to Clipboard'}
            </button>
            <button 
              onClick={handleDownload}
              className="px-6 py-2 text-sm font-bold text-white bg-[#002D72] rounded-lg hover:bg-[#001F4D] shadow-lg transition-all flex items-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
              Download .json
            </button>
          </div>
        </div>

        <div className="bg-[#001F4D] rounded-2xl shadow-2xl p-6 border border-white/10 relative overflow-hidden group">
          <div className="absolute top-4 right-4 text-white/20 font-mono text-xs uppercase tracking-widest font-bold">STOCK PAYLOAD STRUCTURE</div>
          <div className="max-h-[60vh] overflow-y-auto scrollbar-thin scrollbar-thumb-white/10 scrollbar-track-transparent pr-4">
            <pre className="text-blue-100 font-mono text-sm leading-relaxed whitespace-pre-wrap">
              {payloadContent}
            </pre>
          </div>
        </div>

        <div className="p-4 bg-blue-50/50 rounded-xl border border-blue-100 flex items-start gap-3">
          <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center text-onestock-blue shrink-0">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          </div>
          <div className="text-xs text-blue-900/70 leading-relaxed">
            <strong>Integration Tip:</strong> This payload follows the standard OneStock stock import format. Ensure your <code>endpoint_id</code> values match your project's configuration.
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-500">
      {isExportingApi && (
        <StockExportModal 
          stockData={getStockDataArray()} 
          settings={settings} 
          onClose={() => setIsExportingApi(false)} 
        />
      )}

      <div className="flex flex-col md:flex-row items-stretch md:items-center justify-between bg-white px-8 py-6 rounded-2xl border border-gray-200 shadow-sm gap-4">
        <div>
          <h2 className="text-2xl font-bold text-[#002D72]">Inventory Management</h2>
          <p className="text-sm text-gray-500 mt-1">Assign stock quantities per <strong>Endpoint ID</strong> across {products.length} items.</p>
        </div>

        <div className="flex flex-wrap items-center gap-3">
          <div className="relative min-w-[200px]">
            <svg className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
            <input 
              type="text"
              placeholder="Search SKU or Name..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 text-sm bg-gray-50 border border-gray-200 rounded-lg outline-none focus:ring-1 focus:ring-onestock-blue transition-all"
            />
          </div>

          <button onClick={onCancel} className="px-3 py-2 text-xs font-bold text-gray-500 hover:text-red-500 transition-colors">Cancel</button>
          <button onClick={fillRandom} className="px-3 py-2 text-xs font-bold text-onestock-blue border border-onestock-blue rounded-lg hover:bg-blue-50 transition-all">Randomize (50% zeroes)</button>

          <button 
            onClick={generatePayload}
            className="px-4 py-2 text-xs font-bold text-onestock-blue border border-onestock-blue rounded-lg hover:bg-blue-50 transition-all"
          >
            Review JSON
          </button>

          <button 
            onClick={() => setIsExportingApi(true)}
            disabled={!settings.token || !settings.siteId}
            className="px-6 py-2 bg-[#002D72] text-white font-bold rounded-lg hover:bg-[#001F4D] shadow-lg flex items-center gap-2 transition-all text-sm disabled:opacity-30"
          >
            API Synchronize
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden overflow-x-auto">
        <table className="w-full text-left border-collapse min-w-[800px]">
          <thead>
            <tr className="bg-gray-50 border-b border-gray-100">
              <th className="px-6 py-4 text-[10px] font-bold text-gray-400 uppercase tracking-widest w-64">Item Identifier (SKU)</th>
              {settings.stockEndpoints.map(ep => (
                <th key={ep} className="px-4 py-4 text-[10px] font-bold text-[#002D72] uppercase tracking-widest text-center border-l border-gray-100">
                  <div className="flex flex-col items-center gap-2">
                    <span>{ep}</span>
                    <button 
                      onClick={() => applyToColumn(ep)}
                      className="text-[9px] bg-white border border-gray-200 px-2 py-0.5 rounded text-gray-400 hover:text-onestock-blue hover:border-onestock-blue transition-all"
                      title="Apply value to all visible rows"
                    >
                      Apply to all
                    </button>
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-50">
            {filteredProducts.map(p => (
              <tr key={p.sku} className="hover:bg-blue-50/10 transition-colors">
                <td className="px-6 py-4">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded border border-gray-100 overflow-hidden shrink-0">
                      <img 
                        src={p.imageUrl} 
                        alt="" 
                        className="w-full h-full object-cover" 
                        referrerPolicy="no-referrer"
                        onError={(e) => { (e.target as HTMLImageElement).src = 'https://placehold.co/100x100/002D72/white?text=Err'; }}
                      />
                    </div>
                    <div>
                      <div className="text-xs font-bold text-gray-900 truncate max-w-[150px]" title={p.name}>{p.name}</div>
                      <code className="text-[10px] text-gray-400 font-bold">{p.sku}</code>
                    </div>
                  </div>
                </td>
                {settings.stockEndpoints.map(ep => (
                  <td key={ep} className="px-4 py-4 border-l border-gray-50">
                    <input 
                      type="number"
                      min="0"
                      value={stockLevels[p.sku]?.[ep] ?? 0}
                      onChange={(e) => handleStockChange(p.sku, ep, e.target.value)}
                      className="w-full px-3 py-2 bg-gray-50 border border-transparent focus:border-onestock-blue focus:bg-white rounded-lg text-center font-mono font-bold text-onestock-blue outline-none transition-all"
                    />
                  </td>
                ))}
              </tr>
            ))}
            {filteredProducts.length === 0 && (
              <tr>
                <td colSpan={settings.stockEndpoints.length + 1} className="px-6 py-12 text-center text-gray-400 italic">
                  No products found matching your search.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default StepStockUpdate;

import { Product, AppSettings } from '../types';
import { CustomerIdentity } from './geminiService';

export interface OrderGenerationRequest {
  type: 'sfs' | 'ckc' | 'ropis';
  count: number;
  productsPerOrder: number;
  countryCode?: string;
  salesChannel?: string;
  parentOrderId: string;
  orderIdPrefix: string;
  startIndex: number;
  endpointId?: string;
}

const FALLBACK_COUNTRY_DATA: Record<string, { firstNames: string[], lastNames: string[], addresses: { city: string, zip_code: string, lines: string[] }[] }> = {
  FR: {
    firstNames: ["Jean", "Marie", "William", "Elena", "Lucas", "Sophie", "Inès", "Pablo", "Oliver", "Amelia", "Théo", "Léa", "Manon", "Gabriel"],
    lastNames: ["Dupont", "Lefebvre", "Martin", "Bernard", "Dubois", "Thomas", "Robert", "Richard", "Petit", "Durand"],
    addresses: [{ city: "Toulouse", zip_code: "31400", lines: ["8 Rue des Trente-Six Ponts"] }]
  },
  GB: {
    firstNames: ["James", "Mary", "Robert"],
    lastNames: ["Smith", "Jones", "Taylor"],
    addresses: [{ city: "London", zip_code: "W1U 1EE", lines: ["10-12 James St"] }]
  },
  ES: {
    firstNames: ["Antonio", "Maria", "Jose"],
    lastNames: ["Garcia", "Rodriguez", "Gonzalez"],
    addresses: [{ city: "Madrid", zip_code: "28001", lines: ["Calle de Serrano, 1"] }]
  }
};

const getRandom = <T>(arr: T[]): T => arr[Math.floor(Math.random() * arr.length)];

export const generateOrderPayloads = (
  request: OrderGenerationRequest,
  availableProducts: Product[],
  settings: AppSettings,
  aiIdentities?: CustomerIdentity[]
) => {
  const { siteId, token } = settings;
  const now = Math.floor(Date.now() / 1000);
  const oneDay = 86400;

  const cutoff = now + (3600 * 4);
  const etaStart = now + (oneDay * 2);
  const etaEnd = now + (oneDay * 5);

  const parentIdValue = request.parentOrderId;
  const countryCode = request.countryCode || 'FR';
  const fallbackLocalData = FALLBACK_COUNTRY_DATA[countryCode] || FALLBACK_COUNTRY_DATA.FR;

  const mainAiIdentity = aiIdentities && aiIdentities.length > 0 ? aiIdentities[0] : null;
  const mainFirstName = mainAiIdentity ? mainAiIdentity.firstName : getRandom(fallbackLocalData.firstNames);
  const mainLastName = mainAiIdentity ? mainAiIdentity.lastName : getRandom(fallbackLocalData.lastNames);
  const mainTitle = mainAiIdentity ? mainAiIdentity.title : getRandom(['M.', 'Mme', 'Sir']);
  const mainEmail = `alertes_os@onestock-retail.com`; 
  const mainPhone = mainAiIdentity ? mainAiIdentity.phone : (countryCode === 'GB' ? '+44 7123456789' : '+33 612345678');

  const mainBillingAddress = mainAiIdentity ? mainAiIdentity.address : getRandom(fallbackLocalData.addresses);

  const orders: any[] = [];
  let totalParentPrice = 0;
  const currency = availableProducts[0]?.currency || "EUR";

  for (let i = 0; i < request.count; i++) {
    const currentAiId = aiIdentities && aiIdentities[i] ? aiIdentities[i] : null;
    const deliveryAddressData = currentAiId ? currentAiId.address : getRandom(fallbackLocalData.addresses);
    const salesChannel = request.salesChannel || getRandom(settings.orderSalesChannels);

    let subtotal = 0;
    const shuffled = [...availableProducts].sort(() => 0.5 - Math.random());
    const selected = shuffled.slice(0, Math.min(request.productsPerOrder, availableProducts.length));

    const orderItems = selected.map(p => {
      const price = parseFloat(p.price) || 0;
      subtotal += price;
      return {
        item_id: p.sku,
        quantity: 1,
        pricing_details: {
          original_price: price,
          price: price,
          original_unit_price: price,
          unit_price: price
        },
        information: {}
      };
    });

    const shippingPrice = request.type === 'sfs' ? 10 : 0;
    const totalPrice = parseFloat((subtotal + shippingPrice).toFixed(2));
    totalParentPrice += totalPrice;

    const currentIndex = request.startIndex + i;
    const counter = currentIndex.toString().padStart(3, '0');
    const orderId = `${request.orderIdPrefix}${counter}`;

    let orderTypes: string[] = [];
    let deliveryMethod = "standard_hd";
    if (request.type === 'sfs') {
      orderTypes = ['ffs'];
      deliveryMethod = "standard_hd";
    } else if (request.type === 'ckc') {
      orderTypes = ['ffs', 'ckc'];
      deliveryMethod = "standard_ckc";
    } else {
      orderTypes = ['ropis'];
      deliveryMethod = "standard_ropis";
    }

    const orderPayload = {
      site_id: siteId,
      token: token,
      parent_order_id: parentIdValue,
      order: {
        id: orderId,
        types: orderTypes,
        sales_channel: salesChannel,
        date: now,
        delivery: {
          destination: {
            address: {
              city: deliveryAddressData.city,
              contact: {
                title: mainTitle,
                first_name: mainFirstName,
                last_name: mainLastName,
                phone_number: mainPhone,
                email: mainEmail
              },
              lines: deliveryAddressData.lines,
              regions: {
                country: {
                  code: countryCode
                }
              },
              zip_code: deliveryAddressData.zip_code
            },
            ...(request.type !== 'sfs' ? { endpoint_id: request.endpointId || getRandom(settings.stockEndpoints) } : {})
          },
          carrier: {
            name: "mock"
          }
        },
        delivery_promise: {
          original_delivery_option: {
            carbon_footprint: 100,
            cost: shippingPrice || 15,
            cutoff: cutoff,
            delivery_method: deliveryMethod,
            destination: {
              location: {
                country: countryCode,
                zip_code: deliveryAddressData.zip_code
              }
            },
            eta_end: etaEnd,
            eta_start: etaStart,
            shipment_number: 1,
            status: "valid"
          },
          sent_delivery_option: {
            eta_end: etaEnd,
            eta_start: etaStart
          }
        },
        customer: {
          email: mainEmail,
          first_name: mainFirstName,
          last_name: mainLastName,
          phone_number: mainPhone,
          title: "" 
        },
        pricing_details: {
          currency: currency,
          address: {
            city: mainBillingAddress.city,
            contact: {
              title: mainTitle,
              first_name: mainFirstName,
              last_name: mainLastName,
              phone_number: mainPhone,
              email: mainEmail
            },
            lines: mainBillingAddress.lines,
            regions: {
              country: {
                code: countryCode
              }
            },
            zip_code: mainBillingAddress.zip_code
          },
          price: totalPrice
        },
        order_items: orderItems,
        shipping_fees: [
          {
            original_price: shippingPrice,
            price: shippingPrice
          }
        ],
        ...(request.type === 'ckc' ? { sign_on_collect: true } : {})
      }
    };

    orders.push(orderPayload);
  }

  const parentOrderPayload = {
    site_id: siteId,
    token: token,
    parent_order: {
      id: parentIdValue,
      pricing_details: {
        price: parseFloat(totalParentPrice.toFixed(2)),
        currency
      }
    }
  };

  return {
    parent: parentOrderPayload,
    subOrders: orders
  };
};

import React, { useState, useMemo } from 'react';
import { Product, AppSettings, GroundingSource } from '../types';
import ImageModal from './ImageModal';
import EditAssetModal from './EditAssetModal';

interface StepResultsProps {
  products: Product[];
  url: string;
  settings: AppSettings;
  sources?: GroundingSource[];
  selectedIds: Set<string>;
  onSelectionChange: (ids: Set<string>) => void;
  onImport: () => void;
  onCancel: () => void;
  onGenerateJson: (selectedProducts: Product[]) => void;
  onUpdateProduct: (product: Product) => void;
  isHistoryView?: boolean;
}

const StepResults: React.FC<StepResultsProps> = ({ 
  products, 
  url, 
  settings,
  sources = [],
  selectedIds,
  onSelectionChange,
  onImport, 
  onCancel, 
  onGenerateJson, 
  onUpdateProduct,
  isHistoryView = false 
}) => {
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [editingAsset, setEditingAsset] = useState<Product | null>(null);
  const [isMassEditOpen, setIsMassEditOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [massEditField, setMassEditField] = useState<keyof Product>('name');
  const [massEditValue, setMassEditValue] = useState('');

  const filteredProducts = useMemo(() => {
    if (!searchTerm.trim()) return products;
    const lowSearch = searchTerm.toLowerCase();
    return products.filter(p => 
      p.name.toLowerCase().includes(lowSearch) ||
      p.sku.toLowerCase().includes(lowSearch) ||
      p.parentSku.toLowerCase().includes(lowSearch) ||
      p.category.toLowerCase().includes(lowSearch) ||
      p.color.toLowerCase().includes(lowSearch) ||
      p.department.toLowerCase().includes(lowSearch) ||
      p.description.toLowerCase().includes(lowSearch)
    );
  }, [products, searchTerm]);

  const toggleSelectAll = () => {
    const allFilteredSelected = filteredProducts.every(p => selectedIds.has(p.id));
    const newSelected = new Set(selectedIds);

    if (allFilteredSelected) {
      filteredProducts.forEach(p => newSelected.delete(p.id));
    } else {
      filteredProducts.forEach(p => newSelected.add(p.id));
    }
    onSelectionChange(newSelected);
  };

  const toggleSelect = (id: string) => {
    const newSelected = new Set(selectedIds);
    if (newSelected.has(id)) {
      newSelected.delete(id);
    } else {
      newSelected.add(id);
    }
    onSelectionChange(newSelected);
  };

  const handleFieldChange = (product: Product, field: keyof Product, value: string | number) => {
    onUpdateProduct({ ...product, [field]: value });
  };

  const applyMassEdit = () => {
    if (selectedIds.size === 0) return;

    products.forEach(p => {
      if (selectedIds.has(p.id)) {
        let value: any = massEditValue;
        if (['weight', 'length', 'width', 'height'].includes(massEditField)) {
          value = parseFloat(massEditValue) || 0;
        }
        onUpdateProduct({ ...p, [massEditField]: value });
      }
    });

    setIsMassEditOpen(false);
    setMassEditValue('');
  };

  const handleDownloadJson = () => {
    const selected = products.filter(p => selectedIds.has(p.id));
    if (selected.length === 0) {
      alert("Please select at least one article.");
      return;
    }

    const items = selected.map(p => ({
      id: p.sku,
      category_ids: [p.category],
      is_default: true,
      product_id: p.parentSku,
      features: {
        en: {
          color: [p.color],
          departement: [p.department],
          subdepartement: [p.subdepartment],
          image: [p.imageUrl],
          images_big: [p.imageUrl],
          long_description: [p.description],
          name: [p.name],
          price: [p.price],
          size: [p.size],
          weight: [p.weight]
        },
        fr: {
          color: [p.color],
          departement: [p.department],
          subdepartement: [p.subdepartment],
          image: [p.imageUrl],
          images_big: [p.imageUrl],
          long_description: [p.description],
          name: [p.name],
          price: [p.price],
          size: [p.size],
          weight: [p.weight]
        }
      },
      sales_channels_features: {
        [settings.salesChannel]: {
          compare_at_price: parseFloat(p.comparePrice || "0"),
          currency: p.currency,
          price: parseFloat(p.price)
        }
      },
      length: p.length,
      width: p.width,
      height: p.height,
      weight: p.weight
    }));

    const jsonContent = JSON.stringify({ items }, null, 4);
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(jsonContent);
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", `onestock_export_${Date.now()}.json`);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const editableInputClass = "w-full bg-transparent border-none focus:ring-1 focus:ring-onestock-blue rounded px-1 py-0.5 text-inherit transition-all hover:bg-gray-50 focus:bg-white";

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-500 max-w-full relative pb-10">
      {selectedProduct && (
        <ImageModal 
          imageUrl={selectedProduct.imageUrl} 
          productName={selectedProduct.name} 
          onClose={() => setSelectedProduct(null)} 
        />
      )}

      {editingAsset && (
        <EditAssetModal
          product={editingAsset}
          onSave={(newUrl) => handleFieldChange(editingAsset, 'imageUrl', newUrl)}
          onClose={() => setEditingAsset(null)}
        />
      )}

      {isMassEditOpen && (
        <div className="fixed inset-0 z-[110] flex justify-end animate-in fade-in duration-200">
          <div className="absolute inset-0 bg-black/20 backdrop-blur-sm" onClick={() => setIsMassEditOpen(false)}></div>
          <div className="relative w-96 bg-white shadow-2xl h-full p-8 animate-in slide-in-from-right duration-300 border-l border-gray-200">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-bold text-[#002D72]">Mass Edit Selection</h3>
              <button onClick={() => setIsMassEditOpen(false)} className="text-gray-400 hover:text-gray-600">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="space-y-6">
              <p className="text-sm text-gray-500">Apply a new value to all <strong>{selectedIds.size}</strong> selected items.</p>

              <div>
                <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Target Field</label>
                <select 
                  value={massEditField}
                  onChange={(e) => setMassEditField(e.target.value as keyof Product)}
                  className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl text-sm font-bold outline-none focus:border-onestock-blue"
                >
                  <option value="name">Product Name (name)</option>
                  <option value="parentSku">Mother ID (product_id)</option>
                  <option value="description">Description (long_description)</option>
                  <option value="imageUrl">Image URL (image)</option>
                  <option value="category">Category (category_ids)</option>
                  <option value="department">Department (departement)</option>
                  <option value="subdepartment">Sub-Department (subdepartement)</option>
                  <option value="color">Color (color)</option>
                  <option value="size">Size (size)</option>
                  <option value="price">Price (price)</option>
                  <option value="comparePrice">Compare Price (compare_at_price)</option>
                  <option value="weight">Weight (weight)</option>
                </select>
              </div>

              <div>
                <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">New Value</label>
                <input 
                  type="text"
                  value={massEditValue}
                  onChange={(e) => setMassEditValue(e.target.value)}
                  placeholder="Enter value..."
                  className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl text-sm outline-none focus:border-onestock-blue"
                />
              </div>

              <button 
                onClick={applyMassEdit}
                disabled={selectedIds.size === 0}
                className="w-full py-4 bg-[#002D72] text-white font-bold rounded-xl hover:bg-[#001F4D] transition-all shadow-lg flex items-center justify-center gap-2"
              >
                Apply to {selectedIds.size} items
              </button>
            </div>
          </div>
        </div>
      )}

      {sources.length > 0 && (
        <div className="bg-white px-6 py-4 rounded-xl border border-blue-100 shadow-sm animate-in fade-in slide-in-from-top-2">
          <div className="flex items-center gap-2 mb-3">
            <svg className="w-4 h-4 text-onestock-blue" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.899a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" /></svg>
            <h3 className="text-xs font-bold text-onestock-blue uppercase tracking-widest">Grounding Sources (Search Results)</h3>
          </div>
          <div className="flex flex-wrap gap-2">
            {sources.map((source, i) => (
              <a 
                key={i} 
                href={source.uri} 
                target="_blank" 
                rel="noopener noreferrer"
                className="inline-flex items-center px-2 py-1 bg-blue-50 text-onestock-blue text-[10px] font-medium rounded border border-blue-200 hover:bg-blue-100 transition-colors"
              >
                {source.title.length > 30 ? source.title.substring(0, 30) + '...' : source.title}
                <svg className="w-3 h-3 ml-1 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
              </a>
            ))}
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row gap-4 items-stretch md:items-center justify-between bg-white px-6 py-4 rounded-xl border border-gray-200 shadow-sm">
        <div className="flex-1 min-w-0">
          <h2 className="text-xl font-bold text-[#002D72]">Step 2: Hierarchy Verification</h2>
          <p className="text-sm text-gray-500">Edit cells directly. Only selected items ({selectedIds.size}) are used in subsequent tools.</p>
        </div>

        <div className="flex flex-wrap items-center gap-3">
          <div className="relative group min-w-[200px]">
            <svg className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
            <input 
              type="text"
              placeholder="Search items..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 text-sm bg-gray-50 border border-gray-200 rounded-lg focus:ring-1 focus:ring-onestock-blue focus:bg-white outline-none transition-all"
            />
          </div>

          <button 
            onClick={() => setIsMassEditOpen(true)}
            disabled={selectedIds.size === 0}
            className="px-3 py-2 text-xs font-bold text-gray-600 border border-gray-300 rounded-lg hover:bg-gray-50 transition-all flex items-center gap-2 disabled:opacity-30"
          >
            Mass Edit
          </button>

          <button 
            onClick={() => onGenerateJson(products.filter(p => selectedIds.has(p.id)))}
            className="px-3 py-2 text-xs font-bold text-onestock-blue border border-onestock-blue rounded-lg hover:bg-blue-50 transition-all flex items-center gap-2"
          >
            Review JSON
          </button>

          <button 
            onClick={handleDownloadJson}
            className="px-3 py-2 text-xs font-bold text-gray-600 border border-gray-300 rounded-lg hover:bg-gray-50 transition-all flex items-center gap-2"
          >
            Download
          </button>

          {!isHistoryView && (
            <button 
              onClick={onImport}
              className="px-4 py-2 text-xs font-bold text-white bg-[#002D72] rounded-lg hover:bg-[#001F4D] shadow-sm transition-all flex items-center gap-2"
            >
              Validate & Import
            </button>
          )}
        </div>
      </div>

      <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1600px]">
            <thead>
              <tr className="bg-gray-50 border-b border-gray-200">
                <th className="px-6 py-4 w-12 text-center sticky left-0 bg-gray-50 z-10">
                  <input 
                    type="checkbox" 
                    className="w-4 h-4 rounded border-gray-300 text-onestock-blue focus:ring-onestock-blue"
                    checked={filteredProducts.length > 0 && filteredProducts.every(p => selectedIds.has(p.id))}
                    onChange={toggleSelectAll}
                  />
                </th>
                <th className="px-4 py-4 text-[11px] font-bold text-gray-400 uppercase tracking-wider w-32 text-center">Asset</th>
                <th className="px-4 py-4 text-[11px] font-bold text-gray-400 uppercase tracking-wider w-32">Unique SKU</th>
                <th className="px-4 py-4 text-[11px] font-bold text-gray-400 uppercase tracking-wider w-48">Name</th>
                <th className="px-4 py-4 text-[11px] font-bold text-gray-400 uppercase tracking-wider w-64">Description</th>
                <th className="px-4 py-4 text-[11px] font-bold text-gray-400 uppercase tracking-wider w-24 text-right">Price</th>
                <th className="px-4 py-4 text-[11px] font-bold text-gray-400 uppercase tracking-wider w-20 text-center">Size</th>
                <th className="px-4 py-4 text-[11px] font-bold text-gray-400 uppercase tracking-wider w-24 text-center">Weight(kg)</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredProducts.map((product) => (
                <tr key={product.id} className={`hover:bg-blue-50/20 transition-colors ${selectedIds.has(product.id) ? 'bg-blue-50/10' : ''}`}>
                  <td className="px-6 py-4 text-center sticky left-0 bg-inherit z-10 border-r border-gray-50">
                    <input 
                      type="checkbox" 
                      className="w-4 h-4 rounded border-gray-300 text-onestock-blue focus:ring-onestock-blue"
                      checked={selectedIds.has(product.id)}
                      onChange={() => toggleSelect(product.id)}
                    />
                  </td>
                  <td className="px-4 py-4">
                    <div className="flex flex-col items-center gap-1">
                      <div 
                        className="group/asset relative w-10 h-10 rounded border border-gray-200 bg-gray-50 overflow-hidden shrink-0"
                      >
                        <img 
                          src={product.imageUrl} 
                          alt="" 
                          className="w-full h-full object-cover" 
                          referrerPolicy="no-referrer"
                          onError={(e) => { (e.target as HTMLImageElement).src = 'https://placehold.co/100x100/002D72/white?text=Err'; }}
                        />
                        <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover/asset:opacity-100 transition-opacity gap-1.5">
                          <button 
                            onClick={() => setSelectedProduct(product)}
                            className="p-1 bg-white rounded shadow-sm text-onestock-blue hover:bg-blue-50"
                            title="View Image"
                          >
                            <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                          </button>
                          <button 
                            onClick={() => setEditingAsset(product)}
                            className="p-1 bg-white rounded shadow-sm text-onestock-blue hover:bg-blue-50"
                            title="Edit URL"
                          >
                            <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                          </button>
                        </div>
                      </div>
                    </div>
                  </td>
                  <td className="px-4 py-4">
                    <input 
                      className={`${editableInputClass} font-mono font-bold text-[#002D72] text-xs`}
                      value={product.sku}
                      onChange={(e) => handleFieldChange(product, 'sku', e.target.value)}
                    />
                  </td>
                  <td className="px-4 py-4">
                    <input 
                      className={`${editableInputClass} text-sm font-bold text-gray-900`}
                      value={product.name}
                      onChange={(e) => handleFieldChange(product, 'name', e.target.value)}
                    />
                  </td>
                  <td className="px-4 py-4">
                    <textarea 
                      className={`${editableInputClass} text-[10px] text-gray-500 min-h-[40px] resize-none`}
                      value={product.description}
                      onChange={(e) => handleFieldChange(product, 'description', e.target.value)}
                    />
                  </td>
                  <td className="px-4 py-4 text-right">
                    <div className="flex items-center justify-end gap-1">
                      <input 
                        className={`${editableInputClass} text-sm font-bold text-gray-900 text-right w-16`}
                        value={product.price}
                        onChange={(e) => handleFieldChange(product, 'price', e.target.value)}
                      />
                      <span className="text-xs text-gray-400">{product.currency}</span>
                    </div>
                  </td>
                  <td className="px-4 py-4 text-center">
                    <input 
                      className={`${editableInputClass} text-[10px] font-bold text-center w-12 bg-gray-900 text-white rounded`}
                      value={product.size}
                      onChange={(e) => handleFieldChange(product, 'size', e.target.value)}
                    />
                  </td>
                  <td className="px-4 py-4 text-center">
                    <input 
                      type="number"
                      step="0.1"
                      className={`${editableInputClass} text-xs text-gray-500 text-center w-16`}
                      value={product.weight}
                      onChange={(e) => handleFieldChange(product, 'weight', parseFloat(e.target.value) || 0)}
                    />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default StepResults;
